INSERT INTO `topics2_contents` (`id`, `topics2_chapters_id`, `content`, `page`) VALUES
(8487, 2899, '<p><b>Ceramah Master Lu tentang topik khusus: </b><br>Pengetahuan Buddhis tentang Festival Pertengahan Musim Gugur. <br><br><b>Catatan Editor Sekretariat Oriental Radio. <br></b>Festival Pertengahan Musim Gugur adalah salah satu festival tradisional terpenting bangsa Tionghoa, dan juga merupakan \"Hari Kelahiran Suci Bodhisattva Cahaya Bulan\". Orang sering melambangkan kesempurnaan bulan dengan reunifikasi manusia, harmoni dan kesempurnaan; hari ini juga adalah hari ketika banyak Bodhisattva hadir, cocok untuk membaca sutra dan bersujud kepada Buddha lebih banyak. Kita sebagai praktisi Buddha, selama hati kita sempurna, itulah kesempurnaan yang sejati.&nbsp;<br></p>', 1),
(8493, 2902, '<p><b>Pertama, tanya jawab. <br><br>(I) Tentang definisi \"Festival Pertengahan Musim Gugur\" <br><br>1. Penjelasan Master tentang definisi \"Festival Pertengahan Musim Gugur\" </b><br>-Acara Tanya Jawab, 27 September 2015-<br><br>Penelepon: Shifu, hari ini tanggal 15 bulan ke-8ŌĆö Festival Pertengahan Musim Gugur, tolong berikan beberapa kata! <br><br>Master: Festival Pertengahan Musim Gugur, sebenarnya dahulu terutama adalah festival untuk menyembah bulan, karena bulan dapat membuat hati orang menjadi lebih bulat. <br><br>Dahulu dikatakan bulan termasuk yin, \"yin\" berarti suasana hati agak buruk, karena bulan selalu memiliki kekurangan. Manusia mengejar kesempurnaan, ketika tiba Festival Pertengahan Musim Gugur, \"bulan kelima belas bulat dan bulat\", dapat menjadi \"bulat\". Seperti jiwa manusia, jiwa kamu selamanya adalah penafsiran yang keliru, tetapi ketika hati kamu dapat menjadi suatu \"bulat\", yaitu menjadi bulat-sempurna, kamu akan dapat baik. <br><br>Tentu saja di zaman kuno banyak cerita tentang Festival Pertengahan Musim Gugur disebutkan, termasuk \"Chang\'e Terbang ke Bulan\", termasuk suatu harapan yang indah... Ada kisah yang sangat panjang, ada seorang kaisar yang anaknya lahir dengan wajah yang sangat buruk rupa, kemudian karena terus-menerus memuja bulan, akhirnya menjadi sangat cantik, setelah menjadi cantik kemudian menjadi putri. <br><br>Kisahnya sangat panjang, yang mengatakan orang yang sering menyembah bulan akan menjadi semakin cantik, karena bulan termasuk yin, jadi pada tanggal 15 pertengahan musim gugur wanita akan tampak sangat cantik, suasana hati dan berbagai aspek akan sangat sempurna. <br><br>Sebenarnya yang dibicarakan adalah manusia dalam mengejar keindahan suatu sikap tinggi, dalam menyambung medan energi dengan langit. Termasuk banyak legenda indah, Chang\'e, semuanya sangat indah. Jadi, tanggal 15 pertengahan musim gugur, sekarang berbicara tentang \"reuni\", sebenarnya yaitu suatu kesempurnaan dan reuni sikap hati manusia, menjadi semakin sempurna. <br><br>Mengapa Festival Pertengahan Musim Gugur mendapat begitu banyak pengikut? Semua orang mengejar suatu kesempurnaan jiwa di dunia manusia, dan mengejar suatu kesempurnaan dalam bentuk, formalitas, dan tubuh, jadi menganggap hari sempurna ini adalah hari yang membawa keberuntungan kepada dunia manusia. <br><br>Hari keberuntungan seperti ini tidak sepatutnya dilewati dengan mudah, jadi semua orang harus memanfaatkan hari keberuntungan ini untuk dapat menyelesaikan kekhawatiran dalam hati sendiri dengan baik, dapat membuat jiwa sendiri lebih indah. Tidak akan marah pada tanggal 15 pertengahan musim gugur, jika pada tanggal 15 pertengahan musim gugur berbicara lalu ingin marah, itu berarti orang ini memiliki psikologi yang tidak sempurna. <br><br>Penelepon: Mengerti, terima kasih atas pencerahan welas asih Shifu!&nbsp;<br></p>', 1),
(8494, 2902, '<p><b>2. Festival Pertengahan Musim Gugur adalah musim yang diakui langit dan bumi.</b><br>-Acara Tanya Jawab, 20 September 2020-<br><br>Penelepon: Festival Pertengahan Musim Gugur akan segera tiba, apakah dari sudut pandang metafisika banyak Bodhisattva dan dewa pelindung dari langit datang ke dunia manusia? <br><br>Master: Ya. Festival Pertengahan Musim Gugur adalah suatu musim yang diakui langit dan bumi, pada musim ini Bodhisattva akan datang, dan kebetulan ini tanggal 15, pada tanggal 1 dan 15 Bodhisattva memang datang. Ditambah berdasarkan cerita indah Festival Pertengahan Musim Gugur. yaitu Bodhisattva membantu dunia manusia agar bersatu dan bulat.&nbsp;<br></p>', 2),
(8495, 2902, '<p><b>3. Bagaimana membaca sutra pada Festival Pertengahan Musim Gugur? </b><br>-Surat Tanya Jawab, 26 Agustus 2013-<br><br>Tanya: Bagaimana seharusnya membaca sutra pada tanggal 15 bulan ke-8? <br><br>Master: Festival Pertengahan Musim Gugur adalah hari reuni, hati harus bulat; mengekspresikan perasaan rindu dengan keluarga, tetapi tidak harus bersama; hati memiliki Buddha, harus banyak menyebut nama suci Bodhisattva Guanyin, seperti memanggil ibu memanggil Bodhisattva Guanyin, akan mendapat banyak cinta, menghilangkan banyak bencana, pada hari itu dapat membaca \"Na Mo Da Ci Da Bei Guan Shi Yin Pu Sa\" 108 kali, memohon Bodhisattva memberkati seseorang agar selamat.&nbsp;<br></p>', 3),
(8496, 2902, '<p><b>4. Apakah ada penjelasan khusus untuk yang lahir pada Festival Pertengahan Musim Gugur? </b><br>-Surat Tanya Jawab No. 197-<br><br>Tanya: Shifu pernah menjelaskan bahwa yang lahir pada tanggal 1 dan 15 semuanya tidak buruk, secara relatif tanggal 1 lebih baik, mungkin semuanya lebih memiliki jodoh Buddha. Mohon tanya, apakah ada ucapan untuk orang yang lahir pada Festival Pertengahan Musim Gugur? <br><br>Master: Tidak ada ucapan khusus, yang utama melihat akar, akar sangat penting. Seseorang yang bereinkarnasi memiliki orang tua yang baik dan belajar Buddha, dia memiliki akar dasar; orang tua setiap hari bertengkar dan bercerai, anak tidak memiliki akar dasar.&nbsp;<br></p>', 4),
(8497, 2902, '<p><b>5. Penjelasan Master terkait \"Bulan\". </b><br>-Surat Tanya Jawab No. 75-<br><br>Tanya: Orang yang memiliki perasaan khusus terhadap bulan, misalnya sangat menyukai bulan, atau melihat bulan memiliki perasaan khusus yang menyentuh hati, situasi seperti apa ini? Apakah termasuk cenderung yin? <br><br>Master: Memiliki jodoh dengan bulan atau cenderung yin, keduanya mungkin. Orang yang sering menyukai bulan akan cenderung cantik, tetapi energi yin akan cukup berat. Hati yang memiliki bulan tenang dan jernih. Wanita harus lebih tenang, tidak boleh terlalu liar.&nbsp;<br></p>', 5),
(8498, 2903, '<p><b>1. Bagaimana seharusnya Festival Pertengahan Musim Gugur dirayakan?</b><br>-Acara Tanya Jawab, 11 Desember 2011-<br><br>Penelepon: Mohon jelaskan Festival Pertengahan Musim Gugur dari segi metafisika. <br><br>Master: Tanggal 15 bulan ke-8 juga adalah hari raya di langit, adalah hari reuni, hari berkumpul, tetapi bukan berarti semua orang harus lengkap, hanya berharap dapat membawa kebahagiaan kepada semua orang. Sebenarnya seharusnya di rumah membaca sutra dengan baik, memohon keselamatan dan reuni keluarga, sebenarnya pada tanggal 15 bulan ke-8 memohon reuni akan memiliki efek yang sedikit lebih baik daripada memohon pada tanggal 1 dan 15 biasa. Tetapi banyak orang justru makan daging dan ikan besar, setelah tanggal 15 bulan ke-8, ada orang yang meninggal di rumah, jadi sangat dilarang makan makanan laut hidup.<br></p>', 1),
(8499, 2903, '<p><b>2. Ceramah Bodhisattva: Jika pada hari ini dapat bertobat dengan tulus, dosa-dosa masa lalu, semuanya akan lenyap! </b><br>-Surat Tanya Jawab No. 261- <br><br>Tanya: Saya memiliki mimpi yang ingin meminta Shifu membantu memverifikasi. Sekitar jam enam pagi saya bermimpi, diri sendiri di langit, Bodhisattva di langit sangat banyak. <br><br>Di antaranya ada seorang Bodhisattva (saya tidak tahu namanya) bertanya kepada saya, \"Nak, apakah kamu tahu alam 24 langit? <br><br>Saya menggeleng kepala, menjawab, \"Tidak tahu.\" <br><br>Bodhisattva melanjutkan berkata, \"Ini adalah tempat tinggal manusia langit, dewa pelindung sering melindungi Dharma yang benar di sini. 24 langit ini, semua yang terhormat, raja langit dan lain-lain seperti bintang-bintang. Pengemudi XLFM menguasai metode ajaib melampaui duniawi, Dharma yang benar. Mendapat inti ajaran dharma ini, latihan teliti, latihan meditasi, latihan kebijaksanaan baru dapat mencapai pencerahan. <br><br>Nak, tahukah kamu gurumu Master Lu atas perintah Buddha, ingin menyelamatkan semua makhluk yang memiliki jodoh di dunia. Kamu harus tahu gurumu menganggap kekhawatiran makhluk sebagai kekhawatirannya sendiri, penderitaan makhluk sebagai penderitaannya sendiri. Penderitaan kalian seperti ular piton melilit pinggang, akhirnya tidak dapat terikat. <br><br>Sekarang guru yang tercerahkan ada di dunia, jangan dengan hati orang biasa mengukur hatinya, gurumu di sekitar tubuh dewa pelindung banyak seperti rasi bintang, karena itu kata-kata fitnah dunia tidak dapat merusak tekadnya. <br><br>Sekarang melihat orang-orang tidak tahu Bodhisattva agung ada di dunia, dharma ajaib muncul kembali, atau memfitnah, atau dengan dharma lain menyerang dharma kita, melakukan dosa-dosa berat. Para Buddha dan Bodhisattva melihat gurumu tubuh dan pikiran lelah untuk menyelamatkan makhluk di dunia manusia sungguh menyayangi...\" <br><br>Bodhisattva berbicara sampai setengah, saya langsung berlutut. Berjanji kepada bodhisattva. \"Saya bersedia satu pintu tekun melindungi XLFM, belajar dharma Buddha.\" <br><br>Bodhisattva melanjutkan berkata, \"Nak, kamu dapat mengucapkan janji ini, kami sangat senang. Hari ini memanggil kamu datang, adalah tahu sifat Buddha kamu masih ada, hati Buddha belum padam, di tengah jalan mengalami rintangan, bingung tidak maju, kemalasan muncul. <br><br>Hari ini, membawa kamu melakukan pencerahan di atas, masih berharap ingat dalam hati, tidak boleh membuang ke belakang kepala. Sangat tidak boleh meminjam ceramah ini pamer kepada orang-orang dunia. <br><br>Ketika kamu tekun berlatih berhasil, Buddha, Maitreya Buddha, Bodhisattva Nanjing, 60 Tai Sui yang terhormat, Bodhisattva Qielan, Weituo yang terhormat, 500 arhat, Buddha Amitabha, Bodhisattva Guanyin, Bodhisattva Mahasthamaprapta dan lain-lain semua pahlawan besar akan memuji kamu. <br><br>Ada satu hal lagi memberitahu dunia: tanggal 15 bulan ke-8, hari kelahiran suci Bodhisattva Cahaya Bulan, dunia manusia menyebut: pertengahan musim gugur. Sangat jangan meminjam waktu indah ini berbuat jahat, seharusnya dengan hari keberuntungan ini berjanji berbuat baik, berlatih meditasi, jika pada hari ini dapat bertobat dengan tulus, dosa-dosa masa lalu, semuanya akan lenyap! Ingat baik-baik!\" <br><br>Hanya terlihat Bodhisattva ini selesai berbicara semua kata, di langit muncul banyak Bodhisattva, serempak mengatakan kalimat yang sama, \"Melindungi Dharma yang benar, tekun berlatih maju, tunggu kamu membawa teratai pulang!\" <br><br>Master: Kalian lihat gaya bahasa seperti ini, apakah manusia dapat mengatakannya? Sekarang tahu kan, Bodhisattva dan dewa pelindung selalu melindungi XLFM. Bodhisattva sungguh sangat mengharukan. <br><br>Tanggal 15 bulan ke-8, mengapa orang Tiongkok sangat memperhatikan? Hari itu benar-benar tidak boleh berpikir buruk, berbuat jahat, kalau tidak sungguh dosa besar. Tanggal 15 bulan ke-8, bukan reuni manusia dan manusia, tetapi reuni manusia dan langit, banyak Bodhisattva akan turun, ada kata dapat bicara dengan Bodhisattva. Berharap dia tidak sombong, Bodhisattva juga khawatir dia mengambil pencerahan ini untuk congkak dan sombong.<br></p>', 2),
(8500, 2903, '<p><b>3. Tentang masalah membaca Li Fo Da Chan Hui Wen untuk menghilangkan karma pada hari besar seperti pertengahan musim gugur. </b><br>-Acara Zhishuo, 5 September 2014- <br><br>Penelepon: Oriental Radio mengatakan Festival Pertengahan Musim Gugur tahun ini dapat membaca 27 kali Li Fo Da Chan Hui Wen, lalu kita bertobat apakah ditujukan untuk satu hal atau dapat ditujukan untuk beberapa hal lebih baik? <br><br>Master: Jika kamu memiliki beberapa hal kamu katakan, pokoknya dapat menghilangkan satu dua hal. Saya pernah bilang, jika musim besar kamu baca sampai 27 kali dapat menghilangkan banyak rintangan karma. <br><br>Jadi semua orang mengapa pada waktu musim sangat tertarik dengan Li Fo Da Chan Hui Wen ini? Karena kebiasaan buruk manusia adalah, ketika melakukan sendiri bingung lalu berbuat buruk, setelah berbuat buruk lalu mati-matian ingin menghilangkan. Memang pada musim besar ketika bersujud di Bodhisattva sana, mati-matian baca Li Fo Da Chan Hui Wen benar-benar akan terhapus. Kecuali karma pembunuhan tidak bisa terhapus, tetapi karma pembunuhan tidak terhapus juga bisa mengecil. Membaca Li Fo Da Chan Hui Wen benar-benar sangat hebat. <br><br>Penelepon: Ya. Lalu misalnya saya dalam kehidupan ini memiliki karma buruk aborsi, saya pada saat itu pernah bertobat, apakah waktu biasa membaca Li Fo Da Chan Hui Wen hal ini masih bisa diangkat lagi untuk bertobat, betul? <br><br>Master: Boleh, yaitu harus terus bertobat, kamu bertobat sekali lalu tidak bertobat lagi? Kamu kira hilang? Sewaktu kecil tidak sengaja menganiaya seseorang hatimu selalu tidak enak, setiap kali bertobat, sampai kemudian perlahan lupa, itu baru sungguh hilang. <br><br>Penelepon: Mengerti.&nbsp;<br></p>', 3),
(8501, 2903, '<p><b>4. Bagaimana memohon ketika menyebarkan dharma di tempat acara pertengahan musim gugur? </b><br>-Acara Tanya Jawab, 4 Agustus 2013- <br><br>Penelepon: Tanggal 14 September, kami di luar negeri ada sebuah sekolah mengadakan acara pertengahan musim gugur, mengadakan jalan budaya, mempromosikan budaya Tionghua, mereka mengundang kami menaruh buku hasil karya Shifu. Diadakan malam hari di lapangan sekolah, apa kami dapat menyebarkan dharma pada malam hari? <br><br>Master: Benar-benar boleh, kamu hanya perlu di Aula Guanyin dengan Bodhisattva Guanyin dulu bicara waktu ini: \"Berharap Bodhisattva Guanyin dan para dewa pelindung pada malam hari ini dapat membantu kami menyebarkan dharma, kami bersiap menyebarkan dharma.\" Bodhisattva akan merasakan, jadi kamu bisa tenang menyebarkan dharma, tidak akan ada masalah di malam hari, akan diberkati. <br><br>Penelepon: Karena kira-kira ada seribu orang, kami juga berharap pada waktu itu dapat menyebarkan dharma kepada lebih banyak makhluk yang berjodoh, membantu mereka, membuat mereka dapat belajar XLFM dan membaca sutra dengan baik, menyebarkan XLFM ke lebih banyak tempat, membuat setiap tempat kecil mengetahui XLFM. <br><br>Master: Terima kasih semua orang.&nbsp;<br></p>', 4),
(8502, 2903, '<p><b>5. Mengadakan acara pertengahan musim gugur, bolehkah menggantung lentera sebagai hiasan? </b><br>-Acara Tanya Jawab, 21 September 2018-<br><br>Penelepon: Praktisi ingin tanya, jika Aula Guanyin mengadakan acara vegetarian pertengahan musim gugur, bolehkah di area video menggantung beberapa lentera sebagai hiasan? Tidak menyalakan lentera ini. <br><br>Master: Boleh, jangan menyalakan saja boleh. Sebagai hiasan juga bulat sempurna, merah cerah, sangat senang. <br>(Catatan: di rumah tidak cocok begini)&nbsp;<br></p>', 5),
(8503, 2903, '<p><b>6. Apakah Festival Pertengahan Musim Gugur boleh menatap bulan? </b><br><br>Tanya: Ada pepatah \"laki-laki tidak menyembah bintang, perempuan tidak menatap bulan\", mohon tanya apakah kalimat ini masuk akal? Festival Pertengahan Musim Gugur tidak boleh menatap bulan? <br><br>Master: Bulan termasuk yin, perempuan menatap bulan adalah yin ditambah yin. Banyak bintang di langit mewakili dewa, \"menyembah bintang\" mungkin akan muncul penyimpangan, jadi paling baik jangan terlalu banyak terpapar kepada dewa langit bumi, ini mirip alasan ulang tahun tidak meniup lilin. Pada hari bulan penuh pertengahan musim gugur menatap bulan tidak terlalu masalah.&nbsp;<br></p>', 6),
(8504, 2904, '<p><b>(III) Hal-hal yang perlu diperhatikan dan pantangan dalam merayakan Festival Pertengahan Musim Gugur. <br><br>1. Pada Festival Pertengahan Musim Gugur banyak Bodhisattva turun, membunuh makhluk hidup akan mengurangi umur. </b><br>-Acara Tanya Jawab, 26 Oktober 2012- <br><br>Penelepon: Saat membakar dupa pertama pada tanggal 15 bulan ke-8, saya melihat Bodhisattva Guanyin XLFM datang, ayah saya juga bermimpi Bodhisattva datang menyelamatkan anak saya. <br><br>Master:Tentu saja, Bodhisattva pasti datang. <br><br>Penelepon: Saya melepaskan ikan di sebuah kuil, saat melepaskan saya melihat di pintu kuil ada sederetan Bodhisattva berdiri di sana, penuh dengan kegembiraan dharma. <br><br>Master: Sekarang banyak orang bisa melihat Bodhisattva, bisa melihat Bodhisattva adalah hal yang baik. Saya sudah memberitahu kalian sejak lama, Festival Pertengahan Musim Gugur kali ini, kamu tahu ada berapa banyak Bodhisattva yang turun dari langit? Luar biasa banyaknya Bodhisattva. Jadi malam itu jika masih makan ikan besar dan daging, banyak orang akan berkurang umur. Jika malam itu semua orang bersembahyang kepada Buddha, membaca sutra, membakar dupa pertama, saya katakan padamu, akan mengumpulkan berkah dan kebajikan!&nbsp;<br></p>', 1),
(8505, 2904, '<p><b>2. Tanggal 1 dan 15 tidak boleh melakukan hubungan suami istri. </b><br>-Acara Zhishuo, 9 Agustus 2013-<br><br>Master: Tanggal 1 dan 15 banyak Bodhisattva turun ke dunia manusia, jadi tanggal 1 dan 15 tidak boleh berbuat jahat, bahkan suami istri tidak boleh berhubungan badan. <br><br>Hari-hari seperti ini masih ada hari kelahiran Buddha dan Bodhisattva, hari Buddha dan Bodhisattva meninggalkan keduniawian dan hari-hari lain yang memiliki makna peringatan keagamaan, serta beberapa hari raya di dunia manusia, seperti musim semi, Festival Lentera, Festival Pertengahan Musim Gugur, Festival Perahu Naga, dan sebagainya. <br><br>Pada hari-hari ini mengendalikan keinginan, memulihkan tata krama, bukan hanya merupakan penghormatan kepada langit dan bumi, tetapi juga merupakan kelanjutan peradaban tradisional Tiongkok selama ribuan tahun. <br><br>Selain itu, hari-hari raya seperti Qingming, Zhongyuan, Dongzhi dan hari-hari lain yang berkaitan dengan alam baka berenergi yin yang cukup berat, juga tidak cocok melakukan hubungan seksual, mencegah energi yin menempel pada tubuh yang menyebabkan segala urusan tidak berjalan lancar.&nbsp;<br></p>', 2),
(8506, 2904, '<p><b>3. Renovasi yang bertepatan dengan Festival Pertengahan Musim Gugur tidak perlu dihentikan. </b><br>-Surat Tanya Jawab No. 329-<br><br>Tanya: Di tengah-tengah bertepatan dengan tanggal 1, 15, Festival Pertengahan Musim Gugur, Festival Chongyang, apakah perlu menghentikan pekerjaan pada hari itu? <br><br>Master: Sebaiknya jangan renovasi pada Hari Festival Chongyang.&nbsp;<br></p>', 3),
(8507, 2904, '<p><b>4. Ada almarhum yang baru meninggal, bagaimana merayakan hari raya? </b><br>-Surat Tanya Jawab No. 109-<br><br>Tanya: Nenek meninggal belum setahun, apakah ibu boleh membuat ketupat pada Festival Perahu Naga? Orang dahulu mengatakan, jika orang tua meninggal belum setahun, tidak boleh membuat ketupat, juga tidak boleh membuat onde, tidak merayakan pada hari raya seperti Festival Pertengahan Musim Gugur. Apakah XLFM ada penjelasan untuk ini? <br><br>Master: Beberapa adat istiadat masa lalu, sekarang adalah zaman baru, bagi yang percaya Buddha kultivasi hati tidak perlu khawatir, jika ada keluarga meninggal jangan merayakan apapun selama 1 bulan, paling baik tiga bulan.&nbsp;<br></p>', 4),
(8508, 2906, '<p><b>Dua, Pencerahan Master. <br>Pencerahan Master pada tanggal 21 September 2021. </b><br><br><b>Festival Pertengahan Musim Gugur: </b><br>Paling banyak dapat membaca 108 kali Li Fo Da Chan Hui Wen, membakar paling banyak 87 lembar XFZ (Untuk semua penerima dijumlahkan).<br></p>', 1),
(8509, 2908, '<p><b>Kumpulan Dharma Perayaan Festival Chongyang dari Master Lu. <br><br>Catatan Editor: </b><br><br>Festival Chongyang tanggal 9 bulan 9 adalah hari tradisional Tiongkok untuk menghormati, menghargai, dan menyayangi orang tua. Pada hari istimewa ini, dengan memperbanyak perbuatan baik dan berbakti, menghormati orang tua dan berbakti kepada mereka, melakukan kebajikan secara luas, secara alami akan mendapat berkah dan perlindungan Bodhisattva serta pertumbuhan kebajikan. <br><br>Di antara seratus kebajikan, bakti adalah yang utama. Berbakti kepada orang tua adalah tanggung jawab anak-anak, memberikan ketenangan batin dan kepuasan materi kepada orang tua, itulah yang disebut \"bakti\". Orang yang belajar Buddha harus mengikuti jejak Buddha, mempelajari semangat welas asih besar Bodhisattva Guanyin dan Shifu, memandang semua orang tua sebagai orang tua sendiri, dengan hati penuh kasih untuk kepentingan semua makhluk, memperlakukan semua yang berjodoh dengan baik, welas asih tanpa syarat, bersama-sama mencapai Empat Alam Suci.&nbsp;<br></p>', 1),
(8510, 2910, '<p><b>A. Pengenalan Festival Chongyang.<br><br>1. Makna Festival Chongyang tanggal 9-9.</b><br>-Dharma dalam bahasa sederhana, 24 Oktober 2017- <br><br>Tanggal 9 bulan 9 Festival Chongyang adalah hari tradisional Tiongkok. Banyak orang tahu bahwa Tanggal 9 bulan 9 ditetapkan sebagai Festival Chongyang. Sebenarnya dalam \"I Ching\" menetapkan \"6\" sebagai bilangan yin dan \"9\" sebagai bilangan yang. Jadi tanggal 9 bulan 9 adalah hari dan bulan yang sama-sama yang, dua 9 bertemu, sehingga disebut Chongyang (yang berganda). Dua \"9\" persis bertemu bersama, sehingga disebut Chongyang, juga disebut Chongjiu. <br><br>Sebenarnya dalam tradisi Tiongkok, pada masa Dinasti Tang perlahan-lahan terbentuk musim Festival Chongyang yang tetap, agar semua orang dapat memahami. Festival ganda ini sebenarnya berbicara tentang kerinduan orang-orang terhadap orang tua setelah berlalunya tahun-tahun. \"Sembilan\" (jiu) juga bermakna umur panjang, jadi Festival Chongyang 9-9 (jiu-jiu) berarti orang tua harus hidup cukup panjang, semua orang harus makan kue bunga untuk merayakan. Dulu setiap kali bertemu Festival Chongyang, kaisar harus secara pribadi pergi ke Gunung Wansui untuk mendaki tinggi, kemudian di gunung melihat pemandangan sambil melafalkan puisi, dan sebagainya. <br><br>Kebiasaan mendaki tinggi pada Festival Chongyang selalu dipandang sebagai menghindari bencana dan kesulitan. Pada hari Festival Chongyang 9-9, banyak orang suka merawat orang tua, membantu mereka, memberkati mereka agar sehat dan panjang umur. Kemudian bisa tidak ada setan di hati. Festival Chongyang 9-9 juga disebut Festival Mendaki Tinggi. Pada Festival Chongyang semua orang makan kue, kue (gao) berarti \"naik setingkat demi setingkat\".&nbsp;<br></p>', 1),
(8511, 2910, '<p><b>2. Festival Chongyang membahas menghormati orang tua dengan welas asih.</b><br>-Acara tanya jawab, 22 Oktober 2017- <br><br>Festival Chongyang adalah musim tradisional yang sangat besar di Tiongkok, adalah (hari) menghormati orang tua, mempromosikan budaya tradisional Tiongkok, juga hari penyebaran semangat welas asih yang diajarkan Buddha.<br></p>', 2),
(8512, 2911, '<p><b>B. Hal-hal yang perlu diperhatikan saat membaca sutra pada Festival Chongyang.<br><br>1. Pada Festival Chongyang boleh membaca 63 kali Li Fo Da Chan Hui Wen, apa keajaibannya?</b><br>-Acara Zhishuo, 27 Oktober 2017- <br><br>Master: Bodhisattva berkata begitu, maka saya beritahu kalian. 63 kali pasti ada alasannya. 63 kali adalah untuk membuat kalian menghapus lebih banyak karma buruk pada Festival Chongyang. Pasti ada Bodhisattva yang menangani penghapusan karma buruk turun, saya pikir Tujuh Buddha turun. Kamu bisa membaca sebanyak itu karena Tujuh Buddha turun, mereka akan membantumu menghapus.&nbsp;<br></p>', 1),
(8513, 2911, '<p><b>2. Membaca kombinasi sutra untuk memohon kelancaran, apakah akan menghabiskan kebajikan? </b><br>-Acara tanya jawab, 4 November 2018- <br><br>Penelepon: Shifu sebelumnya pernah mengajarkan, boleh membaca 49 kali Ru Yi Bao Lun Wang Tuo Luo Ni pada Festival Chongyang dan 3 kali Da Bei Zhou untuk memohon segala sesuatu berjalan lancar. Mohon tanya Shifu, apakah membaca dua sutra ini sama seperti membaca Zhun Ti Shen Zhou, perlu menghabiskan kebajikan baru bisa berjalan lancar? <br><br>Master: Belum tentu, Meskipun kamu tidak punya kebajikan, membaca ini juga akan menambah kebajikan, hanya masalah jumlah. Jumlah yang banyak baru bisa menambah kebajikan.&nbsp;<br></p>', 2),
(8514, 2911, '<p><b>3. Membaca kombinasi sutra khusus Festival Chongyang memohon kesehatan dan kelancaran akan menggunakan kebajikan.</b><br>-Surat tanya jawab No. 187- <br><br>Tanya: Shifu mengajarkan, boleh membaca kombinasi sutra khusus: 3 kali Da Bei Zhou dikombinasi dengan 49 kali Ru Yi Bao Lun Wang Tuo Luo Ni, sebelum membaca mohon kepada Bodhisattva Guanyin memberkati saya XXX agar segala sesuatu lancar, tubuh sehat. Boleh membaca beberapa set sutra seperti ini pada hari itu (sesuai kemampuan sendiri membaca, jumlah set yang dibaca tidak terbatas), Membaca lebih banyak akan menjamin kelancaran di masa depan. Mohon tanya, memohon seperti ini apakah akan menggunakan kebajikan? <br><br>Master: Akan menggunakan kebajikan.&nbsp;<br></p>', 3),
(8515, 2911, '<p><b>4. Tentang komposisi kebajikan yang digunakan saat membaca kombinasi sutra untuk memohon berkah Bodhisattva.</b><br>-Acara tanya jawab, 19 November 2017- <br><br>Penelepon: Halo Shifu. Shifu dalam ajaran terbaru tentang kombinasi sutra Festival Chongyang: 3 kali Da Bei Zhou dan 49 kali Ru Yi Bao Lun Wang Tuo Luo Ni, mohon Bodhisattva memberkati segala sesuatu lancar, tubuh sehat. Dikatakan akan menghabiskan kebajikan. Mohon tanya, apakah kebajikan dari sutra yang dibaca, atau membaca kombinasi sutra ini membuka kotak kebajikan yang sudah dikumpulkan sendiri, sehingga menggunakan kebajikan sendiri untuk memohon berkah Bodhisattva? <br><br>Master: Tidak peduli kamu membaca XFZ atau sutra, semuanya dapat kebajikan. <br><br>Penelepon: Jadi yang digunakan adalah kebajikan dari kombinasi sutra, atau kebajikan sendiri untuk memohon berkah Bodhisattva? <br><br>Master: Keduanya bisa, Membaca sutra ada kebajikan membaca sutra, diri sendiri juga punya kebajikan diri sendiri. Seperti kamu bekerja di luar mendapat gaji dan uang yang disimpan di rumah sendiri, itu satu konsep. Dari mana kamu mengambil itu urusanmu sendiri. <br><br>Penelepon: Mengerti, tergantung saat kita memohon lebih menekankan aspek yang mana, begitu? Master: Benar.&nbsp;<br></p>', 4),
(8516, 2911, '<p><b>5. Apakah kombinasi sutra khusus yang dibaca pada hari Festival Chongyang berlaku untuk hari biasa? </b><br>-Surat tanya jawab No. 264- <br><br>Tanya: Shifu mengajarkan, bisa membaca kombinasi sutra khusus pada hari Festival Chongyang 3 kali Da Bei Zhou dan 49 kali Ru Yi Bao Lun Wang Tuo Luo Ni. Mohon tanya, apakah hanya boleh dibaca satu hari pada Festival Chongyang? Atau biasanya juga boleh dibaca beberapa kali sesuai jodoh untuk memohon misalnya urusan pekerjaan dan bisnis? <br><br>Master: Boleh dibaca, tapi harus memohon secara khusus.&nbsp;<br></p>', 5),
(8517, 2911, '<p><b>6. Pada Festival Chongyang berikrar seperti ini, Pelindung Dharma akan membantu menambah kebajikan. </b><br>-Acara Zhishuo, 27 Oktober 2017- <br><br>Penelepon: Shifu, kemarin malam bermimpi, mimpi saya bertanya kepada Shifu, \"Shifu, mohon jelaskan Festival Chongyang dari sudut pandang metafisik.\" Dijawab, \"Kamu tunggu sebentar, saya tanya Bodhisattva Guanyin dulu.\" Apa artinya ini? <br><br>Master: Hehe, lihat... kalian harus belajar dari Shifu ya, Shifu tidak pernah berani bicara sembarangan. \"Saya tanya Bodhisattva Guanyin\", adalah menjelaskan \"Festival Chongyang 9-9\" dari sudut ajaran Buddha, bukan hanya dari arti kata, \"Festival Chongyang 9-9\", misalnya Festival Pendakian, memahami dari cerita sejak zaman dahulu, tetapi dari sudut ajaran Buddha, apa yang diwakili Festival Chongyang. Naik setingkat demi setingkat, pada Festival Chongyang kamu harus lebih maju lagi, harus tekun berlatih, harus berikrar, melepas makhluk hidup... melepas kehidupan... itu juga Tiga Senjata Dharma ah. <br><br>Penelepon: Benar. Saat itu Shifu bilang tanya Bodhisattva, saya pikir apa artinya, pasti ada informasi penting, bukan begitu Shifu? Master: Festival Chongyang adalah berlapis ya, berlapis adalah rajin, adalah berusaha ke atas, mengerti? <br><br>Penelepon: Mengerti. Shifu, Festival Chongyang adalah untuk berbakti kepada orang tua, pada tanggal 9 bulan 9 melepas makhluk hidup untuk orang tua apakah efek memperpanjang umurnya sangat baik? <br><br>Master: Sebenarnya baik untuk semua orang tua. Saat Festival Chongyang, Bodhisattva juga datang, dewa pelindung juga datang, hanya para Bodhisattva yang mengatur surga, mengatur orang tua, mengatur orang yang rajin berusaha melatih hati datang lebih banyak, jadi berikrar pada Festival Chongyang sebenarnya sangat baik. Berikirar seperti apa? Berikrar akan rajin berusaha, jika punya hati berbakti, kamu bisa mengikrarkan \"saya ingin lebih berbakti\", hati ini, bicara dengan Bodhisattva. Dulu... saya bukan menyuruh kalian bagaimana terhadap Shifu... saya cerita, dulu di kuil para biksu, mereka terhadap tetua mereka, terhadap guru mereka, juga berikrar, \"kami bersedia bagaimana... mengikuti guru bagaimana...\", sebenarnya ini juga punya kebajikan yang besar. <br><br>Penelepon: Oh. Berikrar saat Festival Chongyang \"menghormati guru dan ajaran\" juga sangat sangat baik, begitu Shifu? <br><br>Master: Yang kamu katakan benar sekali, sangat sangat baik. Dan pada Festival Chongyang kamu asal berikrar \"Saya ingin mengikuti Bodhisattva Guanyin, saya ingin berlatih hati dengan baik... Bodhisattva Guanyin adalah pelita hati saya, saya ingin mengikuti Bodhisattva Guanyin mencapai kesempurnaan dalam 1 kehidupan\", tentu saja ada orang yang tidak bisa melakukan jangan ikrar, atau bilang \"saya selamanya akan memuja Bodhisattva Guanyin, mengikuti Bodhisattva Guanyin belajar Buddha , melatih hati, dan menyelamatkan orang dengan baik\". Kamu berikrar seperti ini saat Festival Chongyang, sebenarnya semua dewa pelindung akan memberi kamu nilai tambah. <br><br>Penelepon: Shifu, \"dewa pelindung memberi nilai tambah\", merujuk pada kebajikan? <br><br>Master: Ya menambah kebajikan. Dewa pelindung kadang menyebut \"memberi nilai tambah\", yaitu menambah kebajikan. <br><br>Penelepon: Mengerti, terima kasih Shifu. <br><br>Master: Sempurna adalah sepuluh penuh, jadi orang bilang \"sepuluh lengkap sepuluh sempurna\" adalah sempurna. Memberi nilai tambah sampai akhirnya sempurna, nilai tidak cukup berarti masih ada karma buruk. Jika kamu bisa mencapai pencerahan tertinggi yang setara dan benar, kamu adalah kebajikan sempurna. <br><br>Penelepon: Shifu, pada hari Festival Chongyang juga banyak Bodhisattva dari surga yang turun, begitu? <br><br>Master: Ingat ya, Bodhisattva akan turun melihat-lihat di semua musim. Ada yang turun menyelamatkan orang, ada Bodhisattva pada hari ini dia datang memperhatikan, memperhatikan orang tua. Nah saat ini kalian kebetulan berikrar dan berbakti kepada ayah ibu atau kakek nenek, atau yang tidak punya kakek nenek ayah ibu, atau terhadap shifu sendiri sebenarnya semua Bodhisattva bisa melihat ini. <br><br>Penelepon: Mengerti. <br><br>Master: Dulu pada Dinasti Tang, saat Festival Chongyang, memberi setiap orang tua makan kueŌĆönaik setingkat demi setingkat, lalu naik ke gunung, mendaki tinggi memandang jauh. Jika di rumah tidak ada kedua orang tua, tidak ada tetua, maka menghormati guru dan menghargai ajaran; dan pergi ke tempat-tempat yang khusus merawat orang tuaŌĆödulu mereka juga punya, bukan sebutan seperti sekarang, seperti \"panti jompo\"ŌĆö tempat di mana orang tua berkumpul, merawat mereka, membantu mereka, sebenarnya ini semua berbuat baik. Saat ini kamu asal membaca beberapa kali Gong De Bao Shan Shen Zhou, kamu mengubahnya menjadi kebajikan. <br><br>Penelepon: Mengerti. Sebenarnya, apa yang Shifu katakan adalah moral tradisional Tiongkok. <br><br>Master: Benar itu adalah moral tradisional Tiongkok. Festival Chongyang punya sumber sejarah. <br><br>Penelepon: Jika terus berbuat baik pada hari Festival Chongyang, berbakti kepada orang tua, menghormati guru dan ajaran, membaca sutra, berikrar, melepas makhluk, bisa baca berapa kali Gong De Bao Shan Shen Zhou di hari ini? <br><br>Master: Boleh bebas baca Gong De Bao Shan Shen Zhou, tidak apa-apa, sutra pendek boleh dibaca sesukanya. <br><br>Penelepon: Baik, terima kasih atas pencerahan welas asih Shifu.<br></p>', 6),
(8518, 2912, '<p><b>C. Kebiasaan hidup dan hal-hal yang perlu diperhatikan terkait \"Festival Chongyang\".</b><br><br><b>1. \"Mendaki tinggi\" pada Festival Chongyang punya makna apa? </b><br>-Acara tanya jawab, 18 Desember 2011- <br><br>Penelepon: Shifu, mengapa pada Festival Chongyang harus mendaki tinggi? Apa makna \"mendaki tinggi\"? <br><br>Master: Mendaki tinggi punya dua makna. Pertama adalah agar kamu pada saat ini bisa meningkatkan tingkatan spiritual. Karena pada Festival Chongyang dan musim lainnya, akan ada banyak Bodhisattva dari dunia bawah atau surga turun. Jika mendaki tinggi, bisa bertemu para Bodhisattva ini. Seperti yang saya katakan membaca sutra di pesawat sangat baik, karena di pesawat adalah mendaki tinggi. Membaca sutra di ketinggian tinggi, bisa menerima medan energi Bodhisattva, sutra yang kamu baca semuanya punya kekuatan spiritual, XFZ akan sangat manjur. Kedua, semua yang bisa mendaki tinggi, berlari ke atas, semuanya baik. Mendaki tinggi pada Festival Chongyang adalah \"wijen berbunga makin tinggi\", yaitu berharap Festival Chongyang hari ini membuat kita berubah nasib, membuat kita makin lama makin baik, seperti tahun baru, \"selamat sejahtera, makin lama makin baik\", prinsipnya sama.&nbsp;<br></p>', 1),
(8519, 2912, '<p><b>2. Mengapa pindah rumah pada hari \"Festival Chongyang\" harus setelah jam 12 siang?</b><br>-Acara tanya jawab, 5 November 2017- <br><br>Penelepon: Shifu, Anda di pertemuan Dharma mengatakan pindah rumah pada Festival Chongyang harus setelah jam 12 siang. Mohon tanya Shifu, apa alasannya? <br><br>Master: Ada musim, biasanya pagi Bodhisattva datang. Dia tinggal di rumahmu atau dia melihat rumahmu, kamu tidak bergerak, maka kamu aman, Bodhisattva tidak akan... dewa pelindung dari dunia surga tidak akan menyelidiki kamu. Kamu diam tidak bergerak, dia tidak menyelidiki lagi; begitu sekali bergerak, dia lihat, \"eh, ini rumah siapa? Ini siapa?\" Contoh sederhana, polisi sedang jaga di samping, banyak orang lihat polisi malah bergerak-gerak, polisi langsung panggil turun; jika kamu tidak bergerak, polisi tidak akan memanggil kamu. Banyak yang nyetir lihat polisi malah tidak bergerak sama sekali, menyetir baik-baik, jangan ganti jalur, kamu ganti jalur dia langsung panggil turun, betul? <br><br>Penelepon: Benar, periksa SIM. Paham. Shifu, pindah rumah pada Festival Chongyang harus setelah jam 12 siang, apakah tanggal 1 dan 15, atau 6 hari puasa, hari suci Buddha dan Bodhisattva, masalah ini juga berlaku? <br><br>Master: Sebenarnya berlaku sama, semua hari besar Bodhisattva datang, siang hari harus hormat. Contoh sederhana, kamu mengundang tamu ke rumah, kamu pindah-pindah barang rumah, masih sempat urus tamu? Setidaknya tidak hormat kan? <br><br>Penelepon: Benar, paham, terima kasih pencerahan welas asih Shifu.&nbsp;<br></p>', 2),
(8520, 2912, '<p><b>3. Berapa lama setelah \"Festival Chongyang\" tidak cocok pindah rumah? </b><br>-Acara tanya jawab, 21 Oktober 2018- <br><br>Penelepon: Berapa lama setelah \"Festival Chongyang\" tidak boleh pindah rumah? <br><br>Master: Umumnya, paling lama satu bulan.&nbsp;<br></p>', 3),
(8521, 2912, '<p><b>4. Ada apa dengan orang yang lahir pada Festival Chongyang? </b><br>-Surat tanya jawab No. 187- <br><br>Tanya: Ada penjelasan apa bagi orang yang lahir pada Festival Chongyang? Apa yang perlu diperhatikan? <br><br>Master: Hargai diri sendiri dengan baik, pasti datang untuk bayar utang.<br></p>', 4),
(8522, 2913, '<p><b>1. Praktisi Buddha harus setia dan berbakti serta bersyukur.</b><br>-Mengetahui sebab memahami akibat, menembus ketidakkekalan, kembali ke diri sejati (Kedua), Taiwan Kaohsiung 22 September 2013- <br><br>Setia dan bakti sangat penting bagi praktisi Buddha. Bakti adalah salah satu fondasi kita belajar Buddha. Banyak orang tidak berbakti, banyak orang tidak punya hati bersyukur, banyak orang tidak menganggap orang lain, sebenarnya setiap orang harus lebih banyak hati terharu dan bersyukur. Mohon tanya semua, apakah kita pernah membasuh wajah dan kaki ayah ibu dengan baik? Padahal orang tua kita sejak kecil membasuh wajah dan kaki kita. <br><br>Praktisi Buddha harus mengerti bersyukur, harus mengerti pikiran baik. Seseorang hidup di dunia, jika tidak punya hati bersyukur, dia tidak akan bisa belajar Buddha dengan baik, dia tidak akan punya sifat Buddha. Master berharap hari ini semua orang yang belajar Buddha yang hadir, kita lebih banyak hati bersyukur kepada orang lain, kita akan lebih punya hati welas asih. (Tepuk tangan).<br></p>', 1),
(8523, 2913, '<p><b>2. Syukur adalah dasar welas asih dan menjadi Buddha.</b><br>-Sekali Tercerahkan adalah Bodhi, melepas terbebas melihat kebenaran sejati, Los Angeles 5 Oktober 2018 (Kedua)- <br><br>Syukur sangat penting, syukur adalah dasar welas asih. Kalian harus belajar setiap hari bersyukur kepada orang lain, bersyukur kepada orang tua. Ada satu lagu yang kalian tahu? Bersyukur orang tua memberi saya kehidupan, bersyukur hidup mengajarkan saya tumbuh, bersyukur kenyataan membuat saya belajar lebih kuat, bersyukur kasih keluarga hangatkan hati, bersyukur cinta kasih tidak berpisah, bersyukur persahabatan lewati badai bersama. Orang yang mengerti bersyukur, keberuntungannya akan makin lama makin baik. Master berharap kalian bersyukur kepada semua orang. Orang yang mengerti bersyukur, dia punya dasar menjadi Bodhisattva. Master ajarkan kalian cara bersyukur ya? Harus belajar menghargai orang lain.&nbsp;<br></p>', 2),
(8524, 2913, '<p><b>3. Hati bersyukur dapat mengubah keberuntungan.</b><br>-Pertemuan jodoh Buddha mendengar suara Buddha, kehidupan Dharma Buddha belajar Guanyin, Brisbane 9 Juni 2019 (Bawah)- <br><br>Banyak orang memperhatikan feng shui. Sebenarnya dalam Buddha terkandung feng shui, karena hati melahirkan segala dharma. Feng adalah medan energi, shui adalah mengalir dan berubah. Seseorang adalah satu feng shui. Feng shui pertama manusia adalah hatimu, feng shui kedua adalah mulutmu, feng shui ketiga adalah perilakumu. <br><br>Seseorang yang sering menyimpan hati bersyukur bisa mengumpulkan cahaya. Cahaya naik ke atas, tampak di wajah adalah senyuman. Wajahmu jika seperti bunga teratai sering tersenyum, kamu pasti orang yang bersyukur, medan energimu bagus, keberuntungan keuangan juga akan bagus. Harmonis menghasilkan kekayaan. Ada orang yang sering iri pada orang lain, benci orang lain, sering mengeluh, medan energi mereka bersifat yin, menerima energi bumi, menerima energi yin, Dari ilmu feng shui, wajahnya adalah wajah labu, wajah pare, karier tidak akan makmur, sulit bertemu orang mulia... <br><br>Pelihara feng shui dalam hatimu, sering bersyukur, kekayaan dan kemewahan makin banyak. Memaksakan diri pakai feng shui energi yin, penderitaan makin banyak. Hati adalah feng, nasib adalah shui. Orang yang ikut jodoh punya feng, orang yang menghargai berkah punya shui. Budaya tradisional Tiongkok bicara, shui adalah keberuntungan keuangan, feng adalah hati welas asih. Punya hati welas asih, bisa memanggil angin dan hujan di dunia manusia.&nbsp;<br></p>', 3),
(8525, 2913, '<p><b>4. Melatih tiga ladang berkah, yaitu orang yang beruntung.</b><br>-Sekali mendengar Buddha sadar sifat kosong, baru tahu tubuh Ini dalam sila, Singapura 17 Mei 2018 (Pertama)- <br><br>Apa itu \"ladang berkah\"? Ladang berkah pertama, mempersembahkan kepada Buddha, Dharma, Sangha, ini adalah ladang hormat. <br><br>Ladang berkah kedua, mempersembahkan kepada orang tua sendiri, Shifu, guru, adalah ladang budi, yaitu ladang tempat kamu membalas budi, karena guru membimbing kamu, Shifu mengajar kamu, orang tua membesarkan kamu, harus berterima kasih. <br><br>Ketiga, mempersembahkan kepada orang miskin. Melihat orang ini sangat miskin, melihat orang ini perlu bantuan, kamu harus bantu dia, melihat orang sakit, orang cacat... sangat kasihan, harus mempersembahkan kepadanya, ini termasuk mengasihi makhluk, disebut ladang kasihan, yaitu dengan hati welas asihmu mempersembahkan kepada orang lain. <br><br>Ada keuntungan apa bagi orang yang punya tiga ladang berkah? Punya tiga ladang berkah, sangat cepat bisa dapat balasan. Banyak orang bilang, \"Mengapa dia meminta manjur, saya meminta tidak manjur?\" Pertama, dia punya bakti; kedua, dia punya hati welas asih; ketiga, dia mengerti hati bersyukur, jadi dia dengan cepat akan menanam kebaikan apa di dunia manusia dapat buah kebaikan apa, dia dalam hati akan punya tiga ladang berkah, orang ini termasuk orang beruntung. (Tepuk tangan).<br></p>', 4),
(8526, 2913, '<p><b>5. Bakti adalah salah satu dasar belajar Buddha.</b><br>-Keadaan baik buruk semua pasrah, welas asih tanpa ego melatih berkah bijaksana (Kedua), Toronto 5 September 2016- <br><br>Ibu selamanya sayang anak, tapi anak sekarang, ada berapa yang benar-benar pantas untuk orang tuanya? Bakti adalah salah satu dasar belajar Buddha, harus berbakti dengan baik, harus punya hati welas asih. Punya hati welas asih harus punya hati bersyukur. Kita manusia dari kecil sampai besar, ada berapa orang yang membantu kita tumbuh, apakah kita bersyukur kepada mereka? Kita menyakiti berapa orang? Lebih banyak pikir tempat baik orang lain, akan tumbuh hati welas asih; setiap hari punya hati welas asih, tidak akan benci orang lain; saat tidak benci orang lain, punya hati bodhi. (Tepuk tangan).<br></p>', 5),
(8527, 2913, '<p><b>6. Hati welas asih berbakti mempersembahkan kepada orang tua, kebajikan luar biasa sulit diukur. </b><br>-Melatih hati adalah bijaksana harus disebarkan, belajar Buddha adalah kebijaksanaan harus diwariskan, Sydney 11 Januari 2020 (Kedua)- <br><br>Dari empat Bodhisattva besar Buddha, yang terkenal dengan \"tekad besar\" dan \"bakti besar\" adalah Bodhisattva Ksitigarbha, pernah dalam kalpa tak terbatas yang lalu menyelamatkan beberapa kehidupan ibunya, membuat ibu lepas dari penderitaan naik ke surga, mendapat kebahagiaan kekal sejati. Buddha pernah berkata kepada murid Ananda, tidak peduli biksu atau umat awam, dengan hati welas asih berbakti mempersembahkan kepada orang tua, kebajikan ini luar biasa sulit diukur. Jadi, jika anak tidak merawat tubuhnya dengan baik, merusak tubuh sendiri, tidak hati-hati, setiap hari sakit, minum alkohol merokok, juga termasuk tidak berbakti. Jadi, kesehatan sangat penting.&nbsp;<br></p>', 6),
(8528, 2913, '<p><b>7. Sebagai anak harus memelihara orang tua.</b><br>-Anak Buddha ujung dunia seperti tetangga, penuh kebahagiaan Dharma dengar suara Buddha, New York, 14 Oktober 2018 (Kedua)- <br><br>Anak domba masih tahu berlutut menyusu, yaitu anak domba kecil saat minum susu ibu harus berlutut minum. Seseorang jika terhadap orang tua yang dengan susah payah membesarkan dirinya, yang budinya seberat gunung, tidak tahu berbakti, maka dia kehilangan hati nurani yang seharusnya dimiliki manusia, kehilangan kualitas moral. Coba pikir, seseorang yang tidak mencintai orang tuanya sendiri, bagaimana anak yang dididiknya bisa berbakti kepadanya? <br><br>Orang tua dan anak, pertemuan seumur hidup ini adalah untuk saling mencintai, bukan untuk saling membenci dan saling membunuh. Hari ini adalah anak, besok mungkin sudah jadi ayah, jadi setiap tindakan harus meninggalkan contoh baik untuk keturunan. Hidup kita ini, jika orang tuamu sangat miskin, kamu harus memberi materi sebagai bakti; jika orang tuamu tua lemah banyak sakit, kamu harus merawat dia sebagai bakti; jika orang tuamu pemarah, kamu harus memahami dia sebagai bakti; jika orang tua berhemat mengurus rumah, kamu harus membantu dia sebagai bakti; jika bertemu orang tua keras kepala, kamu harus mengikuti dia sebagai bakti; orang tua yang cerewet, kamu harus mendengar sebagai bakti. Bantuan orang tua kepadamu bisa membuat mereka terwujud keinginannya, kamu adalah berbakti.&nbsp;<br></p>', 7),
(8529, 2913, '<p><b>8. Orang yang mengerti jalan bakti akan beruntung.</b><br>-Melepas segala jodoh, hati simpan syukur, berlatih hati berlatih perilaku, sempurnakan jalan Buddha, Melbourne 7 Desember 2014 (Kedua)- <br><br>Kebenaran, keadilan, kesopanan, kebijaksanaan, kepercayaan tradisional Tiongkok, bakti adalah dasar pertama belajar Buddha. Ingin punya keberuntungan, harus berbakti. Orang yang mengerti jalan bakti di dunia yang terang pasti akan beruntung.&nbsp;<br></p>', 8),
(8530, 2913, '<p><b>9. Melindungi tubuh sendiri dengan baik juga adalah bakti.</b><br>-Kebaikan welas asih di hati, makhluk samsara dapat pembebasan (Pertama), Taipei 2 Oktober 2016- <br><br>Semua harus mengerti, kita menjalani setiap hari dengan baik adalah tidak mengecewakan orang tua. Master sering dengan banyak umat Buddha berkata harus mengerti berbakti kepada orang tua. banyak anak muda merusak kesehatan sendiri, itu disebut tidak berbakti, karena sakit di tubuh anak, luka di hati ibu. Jika anak terluka, hati ayah ibu paling sedih, jadi, melindungi tubuh sendiri dengan baik, itu juga disebut bakti. Kita menjalani setiap hari dengan baik, adalah memiliki setiap hari sekarang, memiliki sekarang adalah hidup sekarang, hidup saat ini, memiliki hari ini, menang dari seratus kemarin kamu.&nbsp;<br></p>', 9),
(8531, 2913, '<p><b>10. Cinta kepada keluarga meluas ke makhluk, baru akan memiliki welas asih tanpa syarat.</b><br>-Lautan Buddha tanpa batas langit ada batas, welas asih berterima kasih membalas budi Buddha, Kuala Lumpur 27 Agustus 2017 (Pertama)- <br><br>Kalian bayangkan, ibu sayang anak seumur hidup, kita sayang ayah sendiri, sayang ibu sendiri, sayang sesaat. Orang yang belajar Buddha harus mengutamakan bakti, berdasarkan hati welas asih. Jadi, memandang yang lebih tua dari kita, semua harus dipandang sebagai tetua kita; yang lebih kecil dari kita, semua harus dipandang sebagai anak kita; yang seusia dengan kita, harus dipandang sebagai saudara kita, begitu kamu baru akan memiliki welas asih tanpa syarat yang sesungguhnya.<br></p>', 10),
(8532, 2914, '<p><b>E. Apa yang disebut bakti sesungguhnya? <br><br>1. Mengapa bakti menggerakkan langit dan bumi?</b><br>-Acara tanya jawab, 5 Februari 2017-<br><br>Karena saat berbakti, para Bodhisattva di surga itu sangat terharu, mereka merasa kamu sangat sangat baik, terhadap ayah ibu begitu bersyukur. Sebenarnya hati bakti adalah terharu, harus bersyukur. \"Bakti menggerakkan dunia\" adalah prinsip ini. Dahulu Yao Shun Yu, mereka juga sangat berbakti. Shifu dulu sudah cerita dengan kalian, banyak cerita bakti semua bicara, jika kamu berbakti sama dengan kamu punya hati welas asih, juga sama dengan kamu punya hati bersyukur, juga sama dengan kamu sudah melepas diri sendiri, karena hati kamu sepenuhnya hanya ada orang lain tanpa diri sendiri.&nbsp;<br></p>', 1),
(8533, 2914, '<p><b>2. Berbakti kepada orang tua harus dengan hati tulus, secara materi harus memberikan jaminan, sekaligus membacakan sutra dan melepas hewan untuk menanam ladang kebajikan bagi mereka, dengan bakti sekaligus patuh, barulah disebut bakti yang sejati.</b><br>-Acara tanya jawab, 11 Januari 2013- <br><br>Penelepon: Saya punya pertanyaan. Saya mengubah uang yang tadinya untuk berbakti kepada orang tua menjadi membacakan sutra, dan melepas makhluk hidup untuk mereka, tapi jadi jarang mengirim uang kepada mereka. Cara berbakti seperti ini, apakah sesuai Dharma? <br><br>Master: Harus lihat ayahmu sekarang masih punya uang tidak. Jika ayahmu sangat kaya... <br><br>Penelepon: Mereka ada uang pensiun, tapi mungkin keserakahan, kemarahan, kebodohan mereka cukup berat, jadi selalu merasa sangat menderita, yang tidak didapat selalu ingin kejar. <br><br>Master: Baik, tidak usah bicara, kamu sudah mendefinisi mereka, masih perlu saya bicara? Apakah ini baik? Sekarang uang mereka tidak cukup, jadi menggunakan XFZ untuk dipersembahkan? <br><br>Penelepon: Bukan, maksudku mengubah caranya untuk menanam ladang kebajikan bagi mereka. <br><br>Master: Kamu harus ingat, menanam ladang berkah harus niat tulus. Misalnya kamu berbakti ke orangtua, orangtua juga kekurangan uang, kamu juga ingin menanam ladang berkah untuk mereka, maka kirim uang, juga bacakan XFZ untuk mereka, itu disebut bakti sejati, baik bakti maupun patuh, betul? Kamu tidak mau keluar uang, simpan uang, lalu bacakan XFZ untuk mereka, niat ini tidak benar, jadi hal yang dilakukan salah, mengerti? Niat, belajar Buddha harus berniat. Jika kamu dengan Bodhisattva bicara, kamu memang uang tidak banyak, kamu bilang \"saya mau baca lebih banyak XFZ untuk ayah saya\", itu konsep lain.&nbsp;<br></p>', 2),
(8534, 2914, '<p><b>3. Bagaimana memahami \"bakti\" dan \"patuh\".<br></b>-Acara tanya jawab, 9 September 2018- <br><br>Penelepon: Shifu, sekarang banyak orang tua menganggap anak mendengar kata mereka, patuh tanpa syarat baru bakti, tidak patuh adalah tidak bakti, apakah pemahaman seperti ini benar?<br><br>Master: Sama sekali salah. \"Bakti\" dan \"patuh\" sendiri sudah tidak sama. \"Bakti\" adalah baik kepada orang tua, beli barang, rawat, ini disebut bakti; Apa itu \"patuh\"? Ikuti kemauan orang tua. Jika sikap orang tua tidak baik, bagaimana kamu ikuti dia? Dia menyuruhmu mencuri dan mengurangi kerja di kantor, kamu juga mengikutinya? <br><br>Penelepon: Tidak boleh. Master: Itulah prinsipnya. Mengapa harus bakti? Dalam \"Dua Puluh Empat Bakti\" membahas adalah bakti, kan? <br><br>Penelepon: Shifu, bagaimana yang disebut bakti yang sejati? <br><br>Master: Mengutamakan jalan bakti, dengan hati yang patuh sebagai pendamping. Jika semua perkataan orang tua benar, dia merasa benar, dia harus mengikuti orang tua. Tetapi tidak peduli bagaimana salahnya sikap orang tua, kamu tetap harus bakti. <br><br>Penelepon: Mengerti. Ada beberapa umat Buddha yang tidak sering pulang melihat orang tua, tetapi mereka sering melepas makhluk dan membakar XFZ untuk orang tua, apa ini juga satu jenis bakti? <br><br>Master: Ini sudah bakti besar, bukan bakti kecil. Bagaimana dengan para biksu? Mereka jauh dari orang tua mereka, tetapi mereka setiap hari berdoa untuk ayah dan ibu, membuat ayah dan ibu senang; diri sendiri berbuat kebajikan, melindungi orang tua mereka sendiri. <br><br>Penelepon: Mengerti.&nbsp;<br></p>', 3);
INSERT INTO `topics2_contents` (`id`, `topics2_chapters_id`, `content`, `page`) VALUES
(8535, 2914, '<b>4. Berbakti kepada orang tua tidak mempertanyakan karma kehidupan lalu, jodoh kehidupan ini diselesaikan di kehidupan ini. <br></b>-Acara tanya jawab, 25 Mei 2012- <br><br>Penelepon: Saya dengan ibu saya ada sedikit... saya sering seperti sangat benci dia, tapi saya juga cukup sayang dia... <br><br>Master: Tidak boleh benci. Tidak peduli hubungan kehidupan lalu seperti apa, di kehidupan ini adalah ibumu, kamu harus berbakti. Kamu harus mengerti, banyak hal kehidupan lampau, kalau kehidupan ini masih berbuat sembarangan, kehidupan berikutnya harus bayar utang lagi, kapan bisa lunas? Masih harus menderita!', 4),
(8536, 2915, '<p><b>F. Sikap menghadapi penuaan, jalan panjang umur <br><br>1. Dengan sikap apa menghadapi penuaan: Bersedekah kasih sayang, sikap hati selamanya tidak tua.</b><br>-Sifat Buddha selalu ikuti sifat sendiri berjalan, luas selamatkan yang berjodoh dengar suara Buddha (Kedua). Ringkasan acara pertemuan Dharma Taiwan Taipei, 1 Oktober 2016.- <br><br>Kita tidak perlu khawatir untuk kehidupan kita, karena kamu lihat kamu menua, orang lain juga menua, dunia ini siapa pun akan tua, tetapi hati kita tidak pernah tua, karena hati kita tumbuh dalam menolong orang lain, mengasihi orang lain, tumbuh dalam mengasihi orang lain, welas asih kepada orang lain, jadi hati kita selamanya begitu baik hati, hati nurani selamanya begitu manis. Mengapa orang yang belajar Buddha bisa mengalahkan keserakahan sendiri? Karena sendiri memiliki cinta, dan bersedekah cinta ini kepada orang lain, dari orang lain kembali mendapat lebih banyak cinta kasih, memiliki cinta welas asih.&nbsp;<br></p>', 1),
(8537, 2915, '<p><b>2. Keadaan psikologis akan tercermin di wajah. </b><br>-Sifat asli hati nurani bantu orang berjalan, jodoh Buddha jodoh baik welas asih berjalan Ringkasan acara pertemuan Dharma New York, 13 Oktober 2018 (Kedua).- <br><br>Banyak pak tua bersemangat, karena memberikan cinta kepada teman Buddha. Saya benar-benar berterima kasih pada kalian, kalian setiap hari menyebarkan Dharma, perilaku kalian membuat anak-anak kalian lebih menghormati kalian, terima kasih welas asih kalian. Mengapa orang setelah tua, ada yang alis mata baik hati, ada yang wajah penuh kekhawatiran, seperti penuh keluhan? Pernah melihat banyak nenek baik hati, saat muda sudah mempertahankan hati yang penuh cinta kepada dunia, tua mereka tetap baik hati membantu orang; sedangkan yang setiap hari mengeluh tidak karuan, distorsi psikologis mereka sudah tercermin di wajah. Setiap hari tertawa, sepuluh tahun muda. Berharap semua pakai hati welas asih hidup di dunia, akan mendapat lebih banyak kasih sayang.&nbsp;<br></p>', 2),
(8539, 2915, '<p><b>3. Rahasia panjang umur: Simpan kebaikan orang lain kepada diri sendiri di hati.<br></b> -Pelita Dharma Buddha sinari hati, welas asih Guanyin siram dunia manusia Ringkasan acara pertemuan Dharma Jakarta, Indonesia, 23 April 2017 (Kedua).- <br><br>Seorang lansia bernama Zhang Qingsong, pada usia 93 tahun, masih bersemangat tinggi, pikiran tajam. Lansia ini setiap hari bangun jam 7, istirahat jam 2 dini hari, setiap hari belajar Buddha membaca sutra 18 jam, berbaring 3 menit bisa tidur. Dia juga tidak makan vitamin dan supplemen apa pun, tapi selalu minum lesitin untuk menyehatkan otak. <br><br>Ada yang bertanya rahasia panjang umurnya, dia bilang, \"Sangat sederhana, 8 kata: hidup baik, tua baik, sakit baik, mati baik.\" <br><br>Meskipun susah lelah, mengalami cobaan kesulitan dunia manusia berapapun, juga harus punya sikap hati sehat, harus tenang seperti angin ringan awan tipis, lupakan semua hal sedih masa lalu, simpan kebaikan orang lain kepada diri sendiri di hati, baru bisa hati tidak tua, hati selamanya simpan kebahagiaan, inilah rahasia panjang umur lansia ini. <br><br>Orang tua, hati tidak boleh tua. Hati adalah jalan, hati buka jalan buka, hati tersumbat jalan tersumbat. Mengapa bilang \"buka hati\"? Buka hati sendiri, baru bisa menerima energi positif dan qi positif alam semesta langit bumi.&nbsp;<br></p>', 3),
(8540, 2915, '<p><b>4. Hati tidak tua, maka orang tidak tua. </b><br>-Belajar tanpa batas kehidupan bijaksana, lenyap sirna tanpa bocor hati Buddha menyatu (Pertama) Ringkasan acara pertemuan Dharma Makau, 13 Februari 2016.- <br><br>Orang tua, sebenarnya hati yang menua, badan belum tua, hati manusia sudah tua. Konfusius berkata, \"Sebagai manusia, lupakan makan karena tekad, senang sampai lupa khawatir, tidak tahu tua akan datang.\" Sebenarnya menunjukkan, selama hati tidak ada konsep tua, tidak akan tua. <br><br>Di dunia manusia, ada orang meskipun tampak sangat muda, tetapi kekuatan hati menurun, merasa diri sudah tua; ada orang lanjut usia, meskipun sudah berumur, tetapi kekuatan hati kuat, semangat penuh, tua masih gagah, dia tidak merasa diri tua. Manusia hidup di dunia yang paling penting adalah sikap hati. Jika melihat tembus dunia ini, bisa abadi muda, karena kamu tahu semua ini tidak dibawa lahir tidak dibawa mati, saya ada apa yang bisa dirindukan? Beri orang lain ya beri orang lain, tidak ada ya tidak ada, hilang ya hilang, bisa bagaimana saya? Saya hari ini masih bisa hidup dengan baik, saya bersyukur; saya hari ini masih bisa senang menyelamatkan makhluk, membaca sutra, masih bisa punya badan dan panca indra sendiri, itu adalah kebahagiaan.&nbsp;<br></p>', 4),
(8541, 2915, '<p><b>5. Orang yang welas asih berumur panjang. </b><br>-Perasaan Buddha perasaan manusia berkumpul pelabuhan harum, dunia manusia sisakan tanah suci (Pertama) Ringkasan acara pertemuan Dharma, Hong Kong tanggal 2 Juli 2016.- <br><br>Manusia harus ingat: keseimbangan psikologis paling penting. Yang lalu sudah berlalu, kita harus pakai kebaikan dan kebahagiaan menyambut besok. Jadi, orang yang welas asih punya umur. Semua coba pikir dan lihat, semua lansia yang hidup sampai 90 sekian tahun, 100 tahun, mereka semua bisa hidup dalam diri orang lain, karena mereka baik hati, karena mereka welas asih, karena mereka tidak perhitungan dengan orang lain, karena mereka tidak punya hati iri, jadi mereka hidup lama, budaya tradisional Tiongkok mengatakan, orang welas asih sehat, orang yang memilih berlatih akan bebas, akan punya harapan.&nbsp;<br></p>', 5),
(8542, 2915, '<p><b>6. Menjaga muda \"Tiga Karakter\"</b><br>-Tanpa ego lupa diri belajar vajra, welas asih gembira sedekah di kapal welas asih. Ringkasan acara pertemuan Dharma Paris, 7 September 2019 (Kedua).- <br><br>Semua ingat kemarin Master berikan semua \"Tiga Karakter\"? Master tiba-tiba bersemangat puisi, hari ini akan dilanjutkan. Kalian bahagia? <br><br>Hari ini memberikan kalian satu puisi dari tiga karakter: <br>Sering tertawa membuat awet muda sepuluh tahun; <br>sering khawatir membuat rambut memutih; <br>sering marah membuat cepat menua; <br>sering berlari membuat tubuh sehat; <br>berlapang dada menjaga keselamatan; <br>masalah besar dijadikan masalah kecil; <br>belajar Buddha membuat peredaran darah lancar; <br>sering tertawa menghilangkan berbagai penyakit; <br>sering makan vegetarian membuat hati terbuka; <br>tidak takut menua karena sikap hati yang baik; <br>membaca Xin Jing seperti mendengar suara Buddha; <br>berbicara kata-kata baik membuat seperti anak muda; <br>hati welas asih bergantung pada rajin membaca sutra; <br>sering bertobat mengurangi penyesalan; <br>hati yang mudah puas bisa hidup seratus tahun; <br>menjauhi kegelapan nilainya tak ternilai seperti emas.&nbsp;<br></p>', 6),
(8543, 2915, '<p><b>7. Sudah datang maka terima, penderitaan adalah pencerahan. </b><br>-Sekali sadar mendadak melatih bodhi, belajar Buddha tercerahkan mengerti makna sejati (Pertama). Ringkasan acara pertemuan Dharma Los Angeles tanggal 11 September 2016.- <br><br>Seorang nenek berkata kepada saya, \"Master, hari suami saya meninggal, satu malam rambut saya semua memutih.\" <br><br>Saya katakan kepadanya, \"Kamu seperti Wu Zixu melewati gerbang.\" <br><br>Dia bilang, \"Benar. Dulu nonton opera bilang, Wu Zixu tidak bisa lewat gerbang, satu malam cemas sampai rambut jenggot semua putih, sekarang benar-benar ada hal seperti ini.\" <br><br>Berharap semua orang jangan cemas. Sudah datang ke dunia manusia, sudah ada hal terjadi, akan ada cara menghadapinya, ini disebut sudah datang maka terima. Dunia Dharma Buddha mengatakan, setelah penderitaan datang, kebijaksanaanmu akan terlahir, inilah penderitaan adalah pencerahan.&nbsp;<br></p>', 7),
(8544, 2915, '<p><b>8. Orang berlapang dada akan panjang umur. </b><br>-Bodhisattva selalu tinggal di hati, welas asih merasakan hati Buddha (Pertama). Ringkasan acara pertemuan Dharma Perth Australia tanggal 8 Maret 2015.-<br><br>Sebenarnya orang modern ada salah paham tentang kesehatan. Dokter tradisional Tiongkok kuno mengatakan \"orang baik panjang umur\", seseorang sangat baik hati, akan panjang umur; seseorang setiap hari tidak senang, marah, tidak berlapang dada, umur akan pendek. <br><br>Laporan survei sosial pernah melakukan survei, lansia di atas 75 tahun pada dasarnya tidak akan perhitungan untung rugi pribadi. Orang berlapang dada hidup lama, orang berlapang sempit benar-benar akan sakit. Ada orang sering bilang \"saya sangat kesal, saya sangat sedih, kesal sampai makan tidak bisa tidur tidak nyenyak\", benar-benar sangat bodoh. Marah sampai sakit tidak ada yang menggantikannya. <br><br>Jenderal Besar Zhou Yu dibuat kesal hingga mati oleh Zhuge Liang. Orang yang belajar Buddha harus berlapang dada, tidak peduli orang lain bilang apa, tidak peduli orang lain berbuat apa kepadamu, pertama harus mengira orang lain ke arah baik, kedua harus pikir \"dia juga tidak mudah\", inilah welas asih, bisa melarutkan sihir dan rintangan apa pun.&nbsp;<br></p>', 8),
(8545, 2915, '<p><b>9. Lansia melayani anak kecil, akan membuat berkah anak berkurang. </b><br>-Menunggu jodoh matang, penderitaan akan hilang. Acara Tanya Jawab, 8 Januari 2012. (Versi teks rekaman suara) (Pertama).- <br><br>Belajar Buddha adalah menjadi manusia, harus mengerti \"hati ini bisa buat, hati ini bisa lenyap\". Sekarang hati ini sudah sangat tidak baik, serakah, iri, benci orang, hati kita sangat tidak tenang. Hati ini sudah menyebabkan kerusakan pada tubuh dan pikiran kamu, kita harus mengatasinya, kita harus melenyapkannya. Jadi Bodhisattva bilang, hati ini bisa buat, hati ini juga bisa lenyap. <br><br>Jadi Master beritahu semua, harus melanjutkan jodoh baik sendiri. Banyak orang bertemu jodoh baik tidak tahu menghargai, misalnya ayah dan ibu datang ke Australia, membantu kamu mengasuh anak, memasak untuk kamu, \"Ayah, terima kasih!\" \"Ibu, terima kasih!\" Setelah lama, \"Orang tua sialan ini!\" langsung berubah. <br><br>Manusia, tidak menghargai jodoh, tidak menghargai berkah! Tidak menghormati orang adalah tidak menghormati diri sendiri, ada berapa orang bisa memikirkan perasaan orang? <br><br>Orang tua tidak peduli bagaimana, seumur hidupnya sudah berapa banyak menderita dan susah untuk keluarga, sekarang umur sudah tua, rambut sudah putih, masih harus lari ke sini terus melayani kamu, kamu pikir, kamu punya kebajikan apa kemampuan apa? Berapa banyak kehidupan untuk mendapatkan berkah seperti ini? <br><br>Master beritahu semua, jika sering membiarkan orang tua melayani anak kecil, sebenarnya berkah anak kecil ini akan cepat berkurang, inilah mengurangi berkah. Jadi orang pintar, biarkan ayah dan ibu sedikit mengerjakan pekerjaan rumah saja, tidak bisa menjadikan mereka pembantu. Jika kalian menjadikan mereka pembantu, berkah keluarga dan anakmu akan berkurang, dan umurmu akan dikurangi. <br><br>Contoh sederhana, siapa kamu hingga bisa menerima sujud orang tua? Jika orang tua sujud kepada anak kecil, umur anak kecil itu harus dikurangi! Seorang anak kecil bersikap semena-mena kepada kakek neneknya, memukul dan memarahi mereka sesuka hati, sementara mereka harus sabar melihat tingkah lakunya, bahkan di rumah masih khawatir kalau orang tua si anak akan marah, semua ini mengurangi berkah kalian! <br><br>Jangan seperti ini, harus paham! Tidak ada orang yang memberitahu hal ini kepada kalian. Belajar Buddha harus mempelajari hal ini, karena Bodhisattva sering berkata \"berhasil menjadi manusia berarti bisa menjadi Buddha\". Jika kamu menjadi manusia seperti Bodhisattva, kamu adalah Bodhisattva; jika kamu tidak seperti Bodhisattva, bagaimana mungkin kamu bisa berlatih menjadi Bodhisattva?&nbsp;<br></p>', 9),
(8546, 2915, '<p><b>10. Tidak dibawa lahir tidak dibawa mati, tidak seperti cepat lepaskan. </b><br>-Melatih tahan sabar kendalikan hati sendiri, dekati baik jauhi jahat. Ringkasan acara pertemuan Dharma, Malaysia, 3 Maret 2014.- <br><br>Jadi banyak orang seumur hidup tidak tahu apa yang telah mereka lakukan, dengan cepat menjadi kakek dan nenek. Kehidupan manusia kita tidak boleh hidup dalam keinginan, apa saja yang diinginkan, sering kali apa pun tidak didapat, menghabiskan seluruh kehidupan, akhirnya terpaksa meninggalkan dunia ini. Saat pergi apa yang bisa dibawa? Bahkan tubuh sendiri pun tidak bisa dibawa, apalagi yang lain? Usia lanjut, gigi dan rambut rontok habis, badan menjadi sangat kurus. Nenek mana yang bukan berasal dari gadis muda? Mereka saat muda juga sangat cantik, jadi orang muda harus berhati-hati, jangan mengejar lagi. <br><br>Sekali mengejar dengan cepat akan menua, karena tidak bisa mendapatkan yang dikejar, pertama hati akan menua, lalu tubuh menua. Orang yang lelah hati dan tenaga cepat menua. Perjuangan seumur hidup mendapat segalanya, istri, suami, anak, harta, karier... semua pada akhirnya tidak ada apa-apa. Dharma Buddha mengatakan \"kembali ke kekosongan\". Yang kita kejar semuanya tidak ada artinya.<br><br>Bos film Hong Kong Shao Yifu hidup sampai 107 tahun, akhirnya juga hanya dua kata \"hilang semua\". Mengejar dan meminta yang didapat adalah kekosongan. Daripada tahu akhirnya adalah kosong, lebih baik cepat-cepat melepaskan.&nbsp;<br></p>', 10),
(8547, 2915, '<p><b>11. Musuh terbesar merusak kesehatan tidak lain adalah pemarah. <br></b>-Luar biasa jadi suci jodoh surga, selamatkan makhluk jodoh jalan Buddha Ringkasan acara pertemuan Dharma New York, 12 Oktober 2018 (Pertama).- <br><br>Ingat, di antara segala urusan dunia, musuh terbesar merusak kesehatan tidak lain dari kamu pemarah, tidak peduli marah meledak-ledak, atau dendam dalam hati, atau kesal sulit hilang, semua mungkin menyebabkan berbagai penyakit. Pepatah bilang marah cepat merusak badan. Huang Di Nei Jing pernah mengatakan, \"Seratus penyakit lahir dari qi\". Sebenarnya banyak orang dimarahi sampai mati. Dokter sekarang teliti, banyak kanker muncul karena marah. <br><br>Sarjana Tiongkok pernah melakukan statistik dan penelitian terhadap daerah yang banyak orang tua seratus tahun, menemukan ciri umum orang panjang umur berlapang dada, sifat lembut. Rahasia panjang umur nenek adalah memaafkan orang lain, melepaskan diri sendiri. Kamu harus ingat, ketika kamu maafkan orang lain, yang pertama dapat manfaat adalah kamu sendiri. Karena kamu sangat senang, karena kamu lepaskan orang lain, sendiri akan nyaman. Dalam memaafkan orang lain, melepaskan diri sendiri sekaligus, kamu juga membebaskan diri sendiri dari kebencian dan penderitaan. Jadi perangai baik dijalani seumur hidup, alami bisa hidup lama dalam tahun tanpa rintangan.&nbsp;<br></p>', 11),
(8548, 2915, '<p><b>11. Musuh terbesar merusak kesehatan tidak lain adalah pemarah. </b><br>-Luar biasa jadi suci jodoh surga, selamatkan makhluk jodoh jalan Buddha Ringkasan acara pertemuan Dharma New York, 12 Oktober 2018 (Pertama).- <br><br>Ingat, di antara segala urusan dunia, musuh terbesar merusak kesehatan tidak lain dari kamu pemarah, tidak peduli marah meledak-ledak, atau dendam dalam hati, atau kesal sulit hilang, semua mungkin menyebabkan berbagai penyakit. Pepatah bilang marah cepat merusak badan. Huang Di Nei Jing pernah mengatakan, \"Seratus penyakit lahir dari qi\". Sebenarnya banyak orang dimarahi sampai mati. Dokter sekarang teliti, banyak kanker muncul karena marah. <br><br>Sarjana Tiongkok pernah melakukan statistik dan penelitian terhadap daerah yang banyak orang tua seratus tahun, menemukan ciri umum orang panjang umur berlapang dada, sifat lembut. Rahasia panjang umur nenek adalah memaafkan orang lain, melepaskan diri sendiri. Kamu harus ingat, ketika kamu maafkan orang lain, yang pertama dapat manfaat adalah kamu sendiri. Karena kamu sangat senang, karena kamu lepaskan orang lain, sendiri akan nyaman. Dalam memaafkan orang lain, melepaskan diri sendiri sekaligus, kamu juga membebaskan diri sendiri dari kebencian dan penderitaan. Jadi perangai baik dijalani seumur hidup, alami bisa hidup lama dalam tahun tanpa rintangan.&nbsp;<br></p>', 12),
(8549, 2915, '<p><b>12. Tidak puas maka selamanya jauh dari kebahagiaan. </b><br>-Cahaya Buddha menyebar membalas budi Buddha, murid tercerahkan masuk pintu Buddha. Ringkasan acara pertemuan Dharma, 16 April 2017 (Kedua).- <br><br>Orang berbudaya sangat kuat pengendalian diri, bisa mengendalikan diri sendiri. Seseorang tidak peduli bertemu hal apa, bisa mengendalikan, orang ini berbudaya besar, mudah sesuaikan mentalnya. Kehidupan dengan yang lebih rendah dari diri sendiri banding, kerja dengan yang lebih tinggi dari diri sendiri banding, psikologi akan puas, akan seimbang. Lansia harus bicara keseimbangan psikologi, mentalitas damai, bermanfaat untuk panjang umur. Setiap hari tidak akur dengan diri sendiri, setiap hari tidak mengerti, setiap hari tidak jelas, \"Anak tidak baik kepada saya, pasangan tidak baik kepada saya, seumur hidup jual kepada kalian keluarga Zhang keluarga Li\", kapan bisa puas? Tidak puas, selamanya jauh kebahagiaan.<br></p>', 13),
(8587, 2955, '<p><b>Memperingati hari penahbisan Bodhisattva Guanyin tanggal 19 september lunar. </b><br>Kumpulan penjelasan Shifu, 13 Oktober 2022. <br><br><b>Catatan Editor: </b><br>Bodhisattva Guanyin mendengar suara dan menyelamatkan penderitaan, memenuhi semua permohonan, mengemudikan perahu welas asih kembali, dan secara universal menyelamatkan mereka yang memiliki jodoh di dunia Saha ini. Shifu yang penuh welas asih, Lu Junhong mewarisi semangat welas asih agung Bodhisattva Guanyin, menyebarkan XLFM, dan mewariskan Dharma Mahayana. Pada kesempatan Hari Penahbisan Bodhisattva Guanyin, kami secara khusus mengumpulkan ajaran-ajaran terkait dari Shifu untuk dipersembahkan kepada semua makhluk, agar kita dapat mengingat ajaran guru yang penuh welas asih, melaksanakannya sesuai ajaran, mengikuti jejak Buddha, mempelajari semangat welas asih tanpa syarat dan welas asih universal Bodhisattva Guanyin, di bawah bimbingan guru yang penuh welas asih, memberikan manfaat kepada mereka yang memiliki jodoh, dan membuat XLFM terus berlanjut dari generasi ke generasi.&nbsp;<br></p>', 1),
(8588, 2957, '<p><b>(1). Makna nama \"Na Mo Da Ci Da Bei Jiu Ku Jiu Nan Guan Shi Yin Pu Sa\" dan asal usul yang luar biasa.<br><br>1. Apakah yang dimaksud dengan \"Guanyin\"? </b><br>-Hari Kelahiran Bodhisattva Guanyin, 12 Maret 2020- <br><br>Mengapa Bodhisattva Guanyin disebut \"Guan Shi Yin\"? Karena di dunia ini, Bodhisattva Guanyin \"mengamati\" suara makhluk hidup, mencari suara untuk menyelamatkan dari penderitaan, mengikuti suara untuk menyelamatkan orang lain, jadi secara luas dihormati di kalangan rakyat sebagai \"Bodhisattva Guan Shi yin\". Nama lengkap Bodhisattva Guanyin adalah \"Namo Da Ci Da Bei Jiu Ku Jiu Nan Guang Da Ling Gan Guan Shi Yin Pusa Mohe Sa\". \"Da Ci\" berarti mampu memberikan kebahagiaan kepada semua makhluk hidup; \"Da Bei\" mampu menghilangkan semua penderitaan makhluk hidup, menyelamatkan makhluk hidup. Bodhisattva Guanyin adalah seorang Mahabodhisattva agung yang dikenal oleh semua orang, tidak peduli pria, wanita, tua, muda, selama ada penderitaan, kita akan menceritakannya kepada Bodhisattva Guanyin.&nbsp;<br></p>', 1),
(8589, 2957, '<p><b>2. Bodhisattva Guanyin juga dihormati dengan sebutan \"Bodhisattva Avalokite┼øvara\", \"Mah─üsattva Yuantong\", \"Mah─üsattva Guanyin\". </b><br>-Hari Kelahiran Bodhisattva Guanyin, 12 Maret 2020- <br><br>Bodhisattva Guanyin juga disebut \"Bodhisattva Avalokite┼øvara\", dahulu dalam Xin Jing yang diterjemahkan oleh Master Xuanzang, kalimat pertama adalah \"Bodhisattva Avalokite┼øvara (Guanzizai Pusa), ketika melakukan paramita prajna yang mendalam\". Xin Jing adalah sutra yang dapat membuka kebijaksanaan kita, menginspirasi hati welas asih kita, adalah dharma yang dapat melatih telinga untuk mencapai kesempurnaan menyeluruh, dapat mencapai pencerahan. Jadi Bodhisattva Guanyin juga disebut \"Mah─üsattva Yuantong\" dan \"Mah─üsattva Guanyin\". Dalam Buddhisme ada tiga hari peringatan untuk Bodhisattva Guanyin, yaitu tanggal 19 bulan 2, 19 bulan 6, dan 19 bulan 9 dalam kalender lunar, masing-masing adalah Hari Kelahiran Bodhisattva Guanyin, Hari Pencerahan, dan Hari Penahbisan.&nbsp;<br></p>', 2),
(8590, 2957, '<p><b>3. Bodhisattva Guanyin adalah salah satu dari \"Tiga Buddha Suci Barat\", bergelar Tath─ügata Zhengfa Ming, \"berlayar kembali dengan welas asih\" datang ke dunia samsara menyelamatkan makhluk hidup.</b><br>-Ceramah hari kelahiran Bodhisattva Guanyin, 27 Maret 2016- <br><br>Di antara Tiga Suci Barat, posisi berdiri Bodhisattva Guanyin adalah di sebelah atas, di tengah adalah Buddha Amitabha, Bodhisattva Guanyin berada di sebelah atasnya, semua orang tahu sebelah atas adalah tangan kiri, tangan kanan adalah Bodhisattva Mahasthamaprapta, bersama-sama disebut \"Tiga Suci Barat\". <br><br>Bodhisattva Guanyin, sebenarnya sebelum dia datang ke dunia manusia, beliau sudah adalah Tath─ügata Zhengfa Ming, sudah adalah gelar Buddha, beliau pada tanggal 19 bulan 6 berhasil mencapai buah yang benar, memasuki anuttar─ü-samyak-saß╣ābodhi. Makna \"anuttar─ü-samyak-saß╣ābodhi\" adalah sudah memperoleh pencerahan benar tertinggi yang sempurna, jadi setelah Bodhisattva Guanyin setelah mencapai buah yang benar memperoleh pencerahan benar tertinggi yang sempurna, dengan kata-kata sekarang disebut pencerahan total, pemahaman total, terhadap segala sesuatu di dunia ini dia melihat semuanya dengan jelas, pencerahan benar yang sempurna, jadi tingkatan ini menyebutnya Tath─ügata Zhengfa Ming. Banyak orang berkata mengapa disebut \"Tath─ügata\"? Sebenarnya Tath─ügata adalah sebuah gelar, juga adalah Buddha Tath─ügata, \"Tath─ügata\" adalah nama Buddha. <br><br>Bodhisattva Guanyin kemudian dengan identitas Bodhisattva datang kembali atas dasar sumpah, turun lagi dari surga, mengapa banyak orang mengatakan Bodhisattva Guanyin disebut mengemudikan perahu welas asih kembali, apa itu \"mengemudikan kembali\"? Kita berlatih ke atas termasuk yang benar, ke arah \"mengemudikan benar\", perlahan-lahan naik ke atas, naik ke atas... naik sampai kita ke surga sudah menjadi Buddha, menjadi Bodhisattva, maka Bodhisattva dari surga turun lagi ke dunia manusia yang penuh penderitaan, itu dibalik disebut \"mengemudikan kembali\", \"mengemudikan\" adalah sebutan hormat untuk Bodhisattva, jadi disebut \"mengemudikan perahu welas asih kembali\", datang ke dunia Saha untuk secara universal menyelamatkan makhluk hidup. Jadi Bodhisattva Guanyin ada di dalam hati kita, setiap hari di sisi kita. setiap hari di samping kita.&nbsp;<br></p>', 3),
(8591, 2957, '<p><b>4. Bodhisattva Guanyin di masa depan akan menjadi Buddha di Tanah Suci Barat, bergelar \"Tath─ügata Puguang Gongde Shanwang\".</b><br>-Dharma Kelas Murid Sydney, 27 November 2019- <br><br>Di masa depan setelah kalpa yang sangat lama dan tidak dapat dihitung, Buddha Amitabha dari Tanah Suci Barat yang penuh kebahagiaan juga akan Nirvana. <br><br>Setelah Nirvana, waktu Dharma Sejati bertahan di dunia sama dengan umur Buddha Amitabha yang tak terbatas. Makhluk hidup yang diselamatkan oleh Buddha Amitabha ketika masih hidup di dunia dan setelah Nirvana, juga sama-sama tak terbatas dan tak terhingga. Setelah Buddha Amitabha nirvana, mungkin ada makhluk yang tidak dapat melihat Buddha, tetapi jika ada bodhisattva yang dapat membuktikan samadhi mengingat Buddha, maka dapat selalu melihat tubuh Dharma yang tidak musnah dari Buddha Amit─übha. <br><br>(Artinya, Buddha Amitabha sudah tidak menampakkan diri di Tanah Suci Barat, tetapi berada di dalam hati para bodhisattva atau makhluk hidup di Tanah Suci Barat. Contoh sederhana, kalian di dunia manusia, ada tokoh yang sangat agung, kalian sangat mengaguminya, dulu kalian bisa berinteraksi dengannya, berjumpa dengannya, setelah dia nirvana, kalian hanya bisa mengingat dalam hati, selama mengenangnya, kalian dapat merasakan kehadirannya. Prinsipnya sama.)<br><br>Setelah Buddha Amit─übha nirvana, semua benda berharga di Tanah Suci, air yang mengalir, Kolam Tujuh Permata Air Delapan Kebaikan, teratai, pohon permata masih tetap senantiasa mengajarkan suara Dharma, tidak ada bedanya dengan Buddha Amitabha mengajarkan Dharma secara langsung. <br><br>Setelah Dharma benar Buddha Amitabha musnah, melewati tengah malam saat tanda terang muncul, Bodhisattva Guanyin akan duduk bersila di bawah pohon bodhi tujuh permata, mencapai buah Buddha dengan pencerahan benar tertinggi yang sempurna, dengan nama gelar \"Tath─ügata Puguang Gongde Shanwang\". <br><br>Tanah Buddha Bodhisattva Guanyin kelak adalah tujuh jenis permata alami yang tersusun dengan indah, keindahan pemandangan yang megah tidak dapat dihabiskan untuk diceritakan bahkan dalam waktu kalpa yang tak terhingga, satu miliar kali lebih megah daripada Tanah Suci Buddha Jinguang Shizi Youxi. Di sana tidak ada sravaka, pratyekabuddha, semuanya adalah Mahabodhisattva yang telah membangkitkan bodhicitta memenuhi negeri, nama Tanah Suci Buddha itu disebut \"Dunia Kumpulan Semua Permata yang Megah.\" <br><br>Ketika Puguang Gongde Shanwang Rulai ada di dunia, Bodhisattva Mahasthamaprapta akan dekat dan melayani hingga nirvana. Setelah nirvana, Bodhisattva Mahasthamaprapta masih akan mempertahankan dharma benar, setelah dharma benar punah, Bodhisattva Mah─üsth─ümapr─üpta akan mencapai kebuddhaan yang sempurna di negara ini, disebut \"Tath─ügata Shanzhu Gongde Baowang\". Beliau dengan negara Tath─ügata Puguang Gongde Shanwang, cahaya, umur dan jumlah bodhisattva, bahkan waktu Dharma benar bertahan di dunia semuanya sama rata, tidak ada perbedaan.&nbsp;<br></p>', 4),
(8592, 2957, '<p><b>5. Bodhisattva Guanyin pada dasarnya tidak memiliki perbedaan pria dan wanita, untuk menyelamatkan makhluk dengan welas asih mengikuti jodoh menampakkan diri sebagai wanita, mewakili citra ibu yang penuh kasih.</b><br>-Ceramah hari kelahiran Bodhisattva Guanyin, 27 Maret 2016- <br><br>Bodhisattva Guanyin menampakkan 32 wujud. Sebenarnya, selanjutnya saya ingin bercerita kepada kalian, banyak orang agak menganggap pria lebih mulia dari wanita, banyak orang merasa belajar Buddha wanita agak rendah, seperti tidak sebagus pria dalam belajar, atau bagaimana. <br><br>Sebenarnya mengapa Bodhisattva Guanyin di antara 32 wujud, pria dan wanita dia menampakkan keduanya? Bodhisattva Guanyin benar-benar sangat penuh welas asih, dia tahu bahwa wanita terlalu menderita, tahu wanita di dunia ini menderita penderitaan lebih banyak daripada pria, jadi Bodhisattva Guanyin: saya paling penuh welas asih, saya ingin menyelamatkan wanita, bahkan tubuh saya sendiri juga harus berubah menjadi tubuh wanita. <br><br>Karena \"wanita\" mewakili kasih sayang, pikirkan apakah ibu itu kasih sayang? Jadi ayah adalah ayah yang tegas. Tiongkok sejak zaman dahulu mengatakan \"ayah yang tegas ibu yang penyayang\", ibu semua mewakili kasih sayang, ayah semua sangat tegas. Jadi Bodhisattva Guanyin menjelma menjadi citra ibu yang penuh kasih, maka orang menyebut \"Guanyin pemberi anak\", mengapa memohon kepada Bodhisattva Guanyin? Itulah alasannya, jadi kalian harus memahami. <br><br>Sebenarnya Dharma Mahayana memiliki pandangan tentang gender pria dan wanita, yaitu \"semua dharma tidak memiliki bentuk tetap\". Orang yang belajar Buddha tidak peduli kamu belajar baik atau tidak baik, \"semua dharma\", semua metode belajar Buddha tidak membedakan pria dan wanita, artinya wanita dan pria, Bodhisattva membantu kita mengatakan \"harus setara\". <br><br>Jadi \"bukan pria bukan wanita\", artinya tidak ada perbedaan jenis kelamin pria dan wanita, semua belajar Buddha, semua untuk di masa depan dapat berlatih menjadi Buddha. \"Semua wanita juga demikian\", jadi wanita juga begitu, jangan katakan pria bisa berhasil berlatih, wanita juga bisa berhasil berlatih. Ini adalah Bodhisattva Guanyin, pikirkan, dia betapa penuh welas asih. Setelah Shifu menjelaskan kepada kalian, kalian memahami lebih banyak kebenaran. <br><br>Jadi meskipun Bodhisattva Guanyin menampakkan tubuh wanita, seperti kalian yang hadir semua menampakkan tubuh wanita, maka ajaran Buddha mengatakan \"namun bukan wanita\", sebenarnya kalian bukanlah wanita. Artinya, setelah belajar Buddha orang sudah bukan pria bukan wanita, yaitu saya ingin berubah menjadi pria maka jadi pria, saya ingin berubah menjadi wanita maka jadi wanita. <br><br>Di surga, hanya perlu berkata \"hari ini saya ingin berubah menjadi tubuh pria\", maka jadi tubuh pria. Saya berpikir, \"saya berubah menjadi tubuh wanita\", maka tubuh wanita, tubuh langsung berubah. <br><br>Maka di dunia manusia juga demikian, banyak wanita berkata \"hari ini saya harus melakukan pekerjaan pria\", sebenarnya pakaian kerja dikenakan sama dengan pria bekerja; jika hari ini saya ingin berubah menjadi tubuh wanita, penuh welas asih, menjadi orang yang penuh kasih, di rumah memasak, di rumah menggendong anak, dia menjadi tubuh wanita. Bodhisattva memberitahu kita hal-hal ini, \"bukan wanita bukan pria\". <br><br>Jadi di dunia ini, tradisi Tiongkok sering mengatakan ibu welas asih, betul? Karena Bodhisattva Guanyin sendiri menjelma sebagai tubuh wanita adalah untuk membuat kita merasakan simbol welas asih di dunia ini. <br><br>Kita melihat Bodhisattva Guanyin, semua orang tidak berkata apa-apa, tidak peduli orang Barat atau orang Tionghoa, selama kamu melihat... Shifu di sini dulu ada beberapa orang Barat datang berkunjung, dia melihat Bodhisattva Guanyin, langsung menyatukan kedua telapak tangan. Saya tidak pernah mengajarinya, dia melihat, lalu langsung beranjali. Jadi kalian harus mengerti.<br></p>', 5),
(8593, 2958, '<p><b>(2). Wujud agung welas asih Bodhisattva Guanyin dan 32 penjelmaan. <br><br>1. \"Ranting Willow\" memiliki keajaiban apa? </b><br>-Ceramah hari kelahiran Bodhisattva Guanyin, 27 Maret 2016- <br><br>Bodhisattva Guanyin memiliki tiga alat dharma, satu adalah pohon willow, satu adalah botol murni, dan satu lagi adalah singgasana teratai. Singgasana teratai Bodhisattva Guanyin sangat-sangat indah. <br><br>Saya akan membahas ranting willow terlebih dahulu, ranting willow di India adalah tanaman yang dapat menghilangkan penyakit dan kesakitan, dapat memiliki daya hidup. Jadi kalian lihat, jika ranting willow ditancapkan di rumah, tidak mudah layu, tidak seperti bunga lain yang mudah sekali layu, ranting willow yang ditancapkan di sana memiliki daya hidup yang sangat kuat, sehingga ia dapat menyelamatkan orang lain. <br><br>Hanya orang yang kuat yang dapat menyelamatkan orang lain, seseorang harus kuat terlebih dahulu, baru dapat menyelamatkan orang lain; jika dirinya tidak kuat, tidak akan pernah bisa menyelamatkan orang lain. <br><br>Jadi, ranting pohon willow melambangkan berkembang pesatnya ajaran Buddha, Bodhisattva Guanyin memegang ranting pohon willow menunjukkan bahwa ajaran Buddha selalu berkembang pesat, memercikkan air suci kepada kalian, yaitu membantu kalian menghilangkan bencana dan kesulitan.&nbsp;<br></p>', 1),
(8594, 2958, '<p><b>2. Makna \"ranting willow menyiramkan air suci\" Bodhisattva Guanyin. </b><br>-Acara tanya jawab, 8 Januari 2016- <br><br>Ranting willow Bodhisattva Guanyin menyiramkan air suci, sebenarnya ranting willow Bodhisattva Guanyin yang disirami ke dunia manusia bukan memberikan kita sedikit saja, dia membuat seluruh dunia manusia semua makhluk yang menderita dapat memperoleh cahaya welas asihnya. Seperti kita sekarang mengenal Bodhisattva Guanyin, yang dikenal oleh setiap rumah tangga. Pikirkan bagaimana Bodhisattva Guanyin dulu menyelamatkan orang, sebenarnya kisah-kisah ini, di buku, di komputer semua bisa dicari. <br><br>Yang paling utama adalah memberitahu kalian, air botol murni adalah tak terbatas dan tak pernah habis, ranting willow adalah perangkat dharma Bodhisattva Guanyin. Maka dari itu kalian lihat, agama apa pun memiliki upacara ini. Agama Buddha juga ada, mengambil air, mengambil sedikit ranting willow, juga ada upacara ini menyiram sedikit. Kamu lihat Barat memberikan baptisan kepada anak, mereka juga mengambil air untuk dipercikkan kepada orang. Kalian lihat di daerah minoritas etnik China masih ada festival penyiraman air. Sebenarnya maksudnya adalah membawa kebahagiaan kepadamu, mereka menyiramkan air kepadamu, membuatmu basah kuyup, kamu juga tidak bisa berbicara, sebenarnya ini dilakukan manusia. Bodhisattva Guanyin hanya cukup sampai di situ, membuatmu merasakan cahaya welas asih Bodhisattva, membuatmu menerima sinar Buddha Bodhisattva, sebenarnya kamu sudah berubah. <br><br>Ketika seseorang akan meninggal, dia hanya perlu merasakan ranting willow Bodhisattva Guanyin memberikan dia siram di kepala, sebenarnya dia sudah mendapat berkah, jadi dia merasa ada harapan, dia tidak akan mati. <br><br>Ada banyak cerita tentang ranting willow Bodhisattva Guanyin menyelamatkan makhluk hidup mimpi terlalu banyak. ada banyak orang akan dieksekusi, sudah diikat di tempat hukuman mati. Bodhisattva Guanyin datang, ranting willow sekali menyiram, hakim ini memutuskan ulang, semua ada kejadiannya. Masih ada banyak orang yang dituduh salah, ketika dikawal di jalan akan ada orang yang datang menyelamatkannya, dulu semua pernah terjadi, Bodhisattva Guanyin akan menyelamatkan semua; masih ada banyak orang saat akan terjadi pertempuran dengan senjata, Bodhisattva Guanyin menyiram ranting willow sekali di surga, senjata tajam mereka patah, kamu lihat peristiwa-peristiwa seperti ini...&nbsp;<br></p>', 2),
(8595, 2958, '<p><b>3. Apa manfaat luar biasa yang ajaib dari air botol suci Bodhisattva Guanyin. </b><br>-Acara bicara langsung, 5 Mei 2017- <br><br>Pertama, membuat kepalamu jernih; kedua, memberikan berkah energi kepadamu; ketiga, membuatmu dapat memiliki tenaga yang cukup untuk menyebarkan dharma secara luas kepada yang memiliki jodoh dharma. Jadi selama air botol bersih Bodhisattva Guanyin dipercikkan kepadamu, kamu harus keluar menyelamatkan orang, dengan demikian, kamu akan membuat air botol suci semakin banyak. <br><br>Bodhisattva Guanyin memercikkan satu tetes ke badanmu, jika benar-benar melakukan dengan baik, akan menjadi satu teko demi satu teko, mungkin satu gentong demi satu gentong air botol bersih akan mengalir di badanmu. Bukan berarti Bodhisattva Guanyin memercikkan satu tetes padamu lalu habis, sebenarnya setelah sampai di badanmu, melalui kontak antara kamu dengannya, satu tetes air botol suci dapat berubah menjadi ribuan tetes, dapat berubah menjadi ribuan gentong. <br><br>Misalnya, satu tetes air botol suci setara dengan \"welas asih\", kamu dapat menggunakan dua kata \"welas asih\" dari Bodhisattva ini untuk menyelesaikan berapa banyak ikatan karma di hatimu. Kamu melihat orang lain sangat kasihan, kamu tidak bertengkar dengan orang lain, betapa nyamannya dirimu sendiri. <br><br>Misalnya, dua orang tidak senang, kamu melihat dia sangat kasihan, kamu melihat bagian kasihan darinya, dengan cepat hatimu menjadi nyaman. Yang pertama diuntungkan adalah kamu, bukan orang lain. Meminta kebijaksanaan Bodhisattva langsung memberikan, jadi harus meminta kebijaksanaan. <br><br>Shifu setiap kali sujud, tidak meminta apa-apa, hanya meminta Bodhisattva Guanyin memberikan saya kebijaksanaan prajna. Bodhisattva sering menyiramkan air botol suci, Shifu mengerti segalanya, dapat menjawab semuanya, inilah kebijaksanaan. Kebijaksanaan itu luar biasa. Kebijaksanaan adalah harta di dalam jiwa, sebuah harta benda di dalam jiwa.&nbsp;<br></p>', 3),
(8596, 2958, '<p><b>4. Wujud agung luar biasa Bodhisattva Guanyin, berubah sesuai dengan hati semua makhluk. </b><br>-Ceramah hari kelahiran Bodhisattva Guanyin, 27 Maret 2016- <br><br>Wujud Bodhisattva Guanyin sangat agung, dan juga penyayang, kalian perhatikan dengan seksama Bodhisattva Guanyin, dapat melihat matanya akan bergerak, akan melihat wujudnya akan berubah. Semakin berat halangan karma yang ada di hatimu, wujud sang Buddha akan sangat agung; ketika hatimu sangat bersyukur, sangat mencintai Bodhisattva Guanyin, wujudnya akan berubah mengikuti hatimu menjadi sangat welas asih dan baik hati. Bodhisattva Guanyin utamanya memegang air botol murni dan pohon willow, inilah air suci yang dipercikkan Bodhisattva Guanyin ke dunia manusia, \"air suci\" yaitu seperti embun yang bersih, membiarkan jiwa dapat murni, dapat memahami, terutama mengerti. Bodhisattva Guanyin utamanya menyelamatkan penderitaan dunia manusia secara menyeluruh, jika badanmu tidak baik, Bodhisattva Guanyin akan datang dengan cepat, jika mengalami kesulitan atau bencana, Bodhisattva langsung tiba.&nbsp;<br></p>', 4),
(8597, 2958, '<p><b>5. Asal usul \"seribu tangan seribu mata\" ŌĆö Bodhisattva Guanyin melahirkan ratusan ribu juta tangan mata untuk menyelamatkan makhluk hidup di mana-mana. </b><br>-Acara tanya jawab murid, Melbourne 2017- <br><br>Sebenarnya yang disebut seribu tangan seribu mata Bodhisattva Guanyin, hanya sebuah perumpamaan, sulit dihitung dengan angka. Buddha dahulu sering mengatakan tak terbatas tak terhingga, tidak ada batas tidak ada tepi. \"Seperti jumlah pasir Sungai Gangga\", pasir Sungai Gangga di India, pasir di tepi laut, kamu katakan jumlah ini bisa dihitung? Jadi Bodhisattva Guanyin melahirkan ratusan ribu juta tangan dan mata, dia semua bisa menyelamatkan kita. Kamu pikirkan, seribu tangan, seribu mata, bisa menyelamatkan seluruh dunia sebanyak ini orang? Artinya adalah memiliki kekuatan dharma tak terbatas tak terpinggir untuk menyelamatkan makhluk hidup.<br></p>', 5),
(8598, 2959, '<p><b>(3). Sumpah agung Bodhisattva Guanyin dan semangat welas asih agung.<br><br>1. Bodhisattva Guanyin berubah menjadi ratusan ribu juta, menyelamatkan semua makhluk enam alam, seribu tempat memohon seribu tempat merespons.</b><br>-Ceramah hari kelahiran Bodhisattva Guanyin, 27 Maret 2016- <br><br>Tubuh Bodhisattva Guanyin dapat berubah menjadi ratusan ribu juta, jadi saya sering berkata kepada kalian bukan seribu tangan seribu mata sesedikit itu, di tubuh Guanyin dia berubah adalah ratusan ribu juta, artinya dia di seluruh dunia... kamu di mana pun memanggil, wujudnya pergi ke sana. Telinganya bisa mendengar, hatinya bisa merasakan, tangannya sekali diulurkan, dia bisa membantumu, membantumu mengobati penyakit, menyelamatkan jiwamu. <br><br>Jadi \"seribu tangan seribu mata\" hanya sebuah gambaran Bodhisattva Guanyin, seperti banyak sekali, Bodhisattva Guanyin menggunakan ratusan ribu juta wujud sebanyak ini, menyelamatkan semua makhluk enam alam. <br><br>Makhluk hidup enam alam termasuk alam binatang, termasuk alam manusia, termasuk hantu neraka, Bodhisattva semua menyelamatkan, Bodhisattva Guanyin tidak hanya menyelamatkan kita manusia. Bodhisattva Guanyin sangat penuh welas asih! Dia sangat kasihan, dia kerja keras! Tahukah kamu? <br><br>Dahulu ada anjing yang hendak dibunuh, sebelum dibunuh ia menjerit dan meraung sangat keras, Bodhisattva pasti akan datang menyelamatkannya. Jika dalam kehidupan sebelumnya kamu pernah berlatih spiritual, lalu di kehidupan ini kamu terlahir sebagai anjing, ketika akan dibunuh dan kamu meraung kesakitan, Bodhisattva bisa mendengar semua, dia bisa membuat orang yang membunuh tiba-tiba pisaunya patah, jadi dulu selama membunuh binatang, jika pisau sampai patah, maka tidak bisa lagi membunuh binatang ini. Kita tahu Bodhisattva Guanyin mendengar suara semua dunia, dia selama mendengar suara... jadi kalian kadang tidak dapat melihat Bodhisattva Guanyin, di jalan raya membaca sutra, \"Bodhisattva Guanyin selamatkan saya\", sekali kamu panggil dia mendengar, dia tidak hanya harus melihat, kamu bicara, panggil bisa, dia adalah seribu tempat memohon seribu tempat merespons.&nbsp;<br></p>', 1),
(8599, 2959, '<p><b>2. Bodhisattva Guanyin \"tergesa menyelamatkan penderitaan\", berubah menjadi ratusan ribu juta, tersebar di sepuluh penjuru negeri Buddha tanpa batas untuk menyelamatkan makhluk. </b><br>-Hari Kelahiran Bodhisattva Guanyin, 12 Maret 2020- <br><br>Jadi, hati Bodhisattva Guanyin menyelamatkan makhluk sangat terburu-buru, sangat cemas, kadang selama kalian ada sedikit saja penderitaan, Bodhisattva langsung datang menyelamatkan semua orang, jadi kita menyebut Bodhisattva Guanyin \"tergesa menyelamatkan penderitaan\". <br><br>Dan Bodhisattva Guanyin tidak meninggalkan Tanah Suci Cahaya Tenang Barat, berubah menjadi ratusan ribu juta, sebenarnya seribu tangan seribu mata Bodhisattva Guanyin hanya sebuah perumpamaan. <br><br>Bodhisattva Guanyin di tanah suci cahaya sunyi dunia kebahagiaan tertinggi Barat dapat berwujud ribuan juta miliar, jadi baru dapat di seluruh dunia, tidak peduli siapa yang memohon, dia semua dapat mengabulkan setiap permohonan. <br><br>Kemudian \"tersebar di sepuluh penjuru negeri Buddha tanpa batas\", Bodhisattva Guanyin di negeri Buddha sepuluh penjuru juga menampakkan wujud berwarna-warni, kemudian menyelamatkan makhluk hidup. Bodhisattva Guanyin di surga, di dunia manusia semua menyelamatkan banyak makhluk hidup.&nbsp;<br></p>', 2),
(8600, 2959, '<p><b>3. Sesuai dengan wujud apa yang seharusnya diselamatkan, maka menampakkan wujud apa dan mengajarkan dharma untuknya; ada perasaan maka merespons, tidak ada sumpah yang tidak diikuti.</b><br>-Hari Kelahiran Bodhisattva Guanyin, 12 Maret 2020- <br><br>Dalam \"Sutra Teratai Dharma yang Indah\", Buddha berkata, \"Sesuai dengan wujud apa yang seharusnya diselamatkan (yaitu kamu seharusnya dengan wujud apa untuk diselamatkan), Bodhisattva Guanyin maka menampakkan wujud apa dan mengajarkan dharma untuknya.\" Seharusnya menggunakan metode apa untuk membantumu, Bodhisattva Guanyin menampakkan wujud seperti apa dan mengajarkan dharma untukmu. <br><br>Bodhisattva Guanyin meskipun masuk ke seluruh negeri Buddha sepuluh penjuru, tetapi dengan dunia penderitaan kita ini jodohnya sangat mendalam. Bodhisattva Guanyin dapat \"mencari suara menyelamatkan penderitaan, menyelamatkan penderitaan menyelamatkan kesulitan\", selama kalian memohon, Bodhisattva datang. <br><br>Dan \"mengikuti jenis menampakkan wujud\", yaitu kamu orang tipe apa, Bodhisattva akan berubah menjadi orang tipe apa datang menyelamatkanmu, datang secara universal menyelamatkan makhluk hidup. <br><br>Dan \"ada perasaan maka merespons\", selama kamu memiliki perasaan, selama kamu merasa \"saya ingin memohon kepada Bodhisattva Guanyin\", banyak orang saat bermimpi, diikat oleh mimpi buruk, ditangkap, selama di dalam mimpi dia memiliki perasaan \"saya ingin memohon kepada Bodhisattva Guanyin\", Bodhisattva Guanyin langsung merespons. <br><br>\"Tidak ada sumpah yang tidak diikuti\" artinya setiap permohonan yang kamu sampaikan, Bodhisattva Guanyin pasti akan mengabulkannya, yang terpenting adalah seberapa kuat keyakinanmu kepada Bodhisattva Guanyin. <br><br>Jadi \"peristiwa ajaib dari masa lampau hingga sekarang sangat banyak dan tidak bisa dihitung semua\" artinya kisah-kisah mukjizat Bodhisattva Guanyin yang Maha Welas Asih itu begitu banyak sehingga tidak mungkin bisa diceritakan semuanya.&nbsp;<br></p>', 3),
(8601, 2959, '<p><b>4. \"Welas asih agung mencabut penderitaan manusia, welas asih agung di dunia manusia\", Bodhisattva Guanyin adalah perwujudan welas asih.</b><br>-Ceramah Hari Kelahiran Bodhisattva Guanyin, 27 Maret 2016- <br><br>Di Tiongkok sebenarnya ada empat Bodhisattva besar, saya yakin banyak dari kalian tahu empat Bodhisattva besar yang mana. Empat Bodhisattva \"kebijaksanaan, welas asih, perbuatan, keinginan\", ini adalah simbol empat Bodhisattva besar Dharma Mahayana. <br><br>Yang pertama adalah \"kebijaksanaan\", semua orang tahu adalah Bodhisattva Manjusri paling memiliki kebijaksanaan; kemudian Bodhisattva Guanyin adalah yang paling welas asih, \"welas asih\", mengasihani makhluk hidup; yang ketiga adalah \"perbuatan besar\", yaitu saya pergi menjalankan sumpah, pergi bertindak, adalah Bodhisattva Samantabhadra; yang terakhir adalah Bodhisattva \"sumpah besar\", yaitu Bodhisattva Ksitigarbha. Ini adalah empat Bodhisattva paling terkenal di Tiongkok, jadi disebut \"kebijaksanaan, welas asih, perbuatan, keinginan\". <br><br>Memberitahu kalian hal-hal ini, yaitu untuk membuat kalian belajar memiliki welas asih agung, di dunia manusia untuk welas asih agung mencabut penderitaan manusia, membantu orang lain mencabut penderitaan. <br><br>Mengapa Shifu sering dalam penyebaran dharma, adalah membantu orang lain mencabut penderitaan dalam hati, tidak membiarkanmu menumpuk di dadamu, setiap hari sedih, setiap hari menderita tak tertahankan. Jadi disebut \"welas asih agung mencabut penderitaan manusia, welas asih agung di dunia manusia\", ini adalah milik Bodhisattva Guanyin. <br><br>Bodhisattva Guanyin karena kualitas karakter menyelamatkan penderitaan menyelamatkan kesulitan di dunia Saha yang nyata, sudah menjadi penjelmaan welas asih. Jadi orang selama melihat Bodhisattva Guanyin, tahu \"aduh, Bodhisattva ini sangat penuh welas asih\". <br><br>Kita belajar Buddha sampai akhirnya, membuat orang lain melihatmu \"aduh, orang ini sangat penuh welas asih\", kamu adalah belajar Bodhisattva Guanyin. Kita semua mencintai Bodhisattva Guanyin, karena Bodhisattva Guanyin di mana-mana mau membantu orang lain. Kita sekarang di dunia manusia, pikirkan, kalian mau tidak mau membantu orang lain? Yaitu orang lain memohon kepadamu, kamu semua tidak mau keluar rumah membantu orang lain. Jadi mampu di mana-mana pergi membantu orang lain, orang itu adalah \"seribu tempat memohon seribu tempat merespons, di lautan penderitaan selalu menjadi perahu menyelamatkan orang\". <br><br>Sebenarnya, Bodhisattva Guanyin adalah terus-menerus membantu orang lain, di lautan penderitaan terus-menerus menyelamatkan penderitaan menyelamatkan kesulitan. Kita tubuh manusia tidak baik, bukankah seharusnya memberikan kenyamanan kepada orang lain? Apakah seharusnya memberitahu ajaran Buddha, memberitahu sutra kepada orang lain, bukan sendiri menikmati? Jadi ini adalah Buddhisme Mahayana. Bodhisattva Guanyin adalah keyakinan kita dan harapan meminta bantuan, ada berapa banyak orang nyawanya akan habis, ada berapa banyak orang kesulitannya terlalu banyak, semua bergantung pada pertolongan Bodhisattva Guanyin.&nbsp;<br></p>', 4),
(8602, 2959, '<p><b>5. Bodhisattva Guanyin di antara semua Buddha dan Bodhisattva adalah yang paling welas asih, hati welas asih paling luar biasa sempurna.</b><br>-Acara tanya jawab, 26 Maret 2017- <br><br>Bahkan Buddha berkata, di surga begitu banyak Bodhisattva, Welas asih Bodhisattva Guanyin nomor satu, \"tidak sebanding\", welas asih semua Bodhisattva tidak sebanding dengan Bodhisattva Guanyin. Karena banyak adalah Bodhisattva Vajrasattva, masih ada beberapa Bodhisattva dalam bidang lain, misalnya dalam hal kebijaksanaan, dalam hal menyelamatkan orang dengan mengorbankan diri sendiri, mereka semua sangat baik, nomor satu, tetapi dalam hal welas asih, memang Bodhisattva Guanyin paling sempurna. Jadi begitu membicarakan Bodhisattva Guanyin, semua orang memuji, bukan berarti Bodhisattva lain tidak penuh welas asih, hanya saja yang paling penuh welas asih adalah Bodhisattva Guanyin.&nbsp;<br></p>', 5),
(8603, 2959, '<p><b>6. Bodhisattva Guanyin memiliki hati yang sangat luas, dapat menampung semua dunia yang tak terhitung jumlahnya, menolong tanpa syarat, menganggap hati makhluk hidup sebagai hatinya sendiri.<br></b>-Ceramah Hari Kelahiran Bodhisattva Guanyin, 12 Maret 2020-<br><br>Bodhisattva Guanyin sangat penuh welas asih, hatinya mencakup seluruh alam semesta, artinya Bodhisattva Guanyin sangat memiliki hati penuh kasih dan welas asih, lapang dadanya sangat besar... banyak orang ketika berdoa kepada Bodhisattva, \"Bodhisattva, saya pasti akan begini begitu\", baik, setelah doanya terkabul, dia menyesal lagi. <br><br>Kita manusia jika mengalami hal-hal seperti ini, kita akan sering tidak senang: kamu lihat, awalnya begitu membantumu, setelah berhasil membantumu, kamu malah berubah pikiran lagi. <br><br>Sedangkan Bodhisattva Guanyin sangat penuh welas asih, lapang dadanya sangat sangat besar, hatinya mencakup seluruh alam semesta, yaitu di ruang angkasa mampu merangkul seluruh dunia yang tak terhitung, menjadikan hati makhluk hidup sebagai hatinya sendiri, yaitu hati kalian adalah hati Bodhisattva, Bodhisattva mampu merasakan penderitaan kalian. \"Menjadikan situasi makhluk hidup sebagai situasinya\", artinya, kalian hari ini mengalami penderitaan, Bodhisattva juga akan menerima penderitaan ini, bersama kalian menanggungnya, inilah Bodhisattva Guanyin. <br><br>Jadi ikatan batin kita dengan Bodhisattva Guanyin tidak dapat diungkapkan habis, dan welas asih Bodhisattva Guanyin pada kita adalah \"menolong tanpa syarat\". Bukan karena kamu pernah beberapa kehidupan yang lalu menyembah Bodhisattva Guanyin, Bodhisattva datang menolongmu, kalau kamu tidak menyembah dia tidak menolong ŌĆö bukan begitu; selama kamu sekarang menyembah, tidak peduli masa lalu ada hubungan atau tidak, Bodhisattva semua akan \"merespons karena ada hubungan\" ŌĆö karena hubunganmu sekarang dia datang menolong. <br><br>Jadi kebijaksanaan duniawi kita orang biasa, perasaan orang biasa, tidak dapat dibandingkan dengan welas asih agung Bodhisattva Guanyin.<br></p>', 6);
INSERT INTO `topics2_contents` (`id`, `topics2_chapters_id`, `content`, `page`) VALUES
(8604, 2960, '<p><b>(4). Belajar semangat welas asih agung yang tanpa batas dan sepenuh hati. <br><br>1. Penderitaan makhluk hidup adalah penderitaan Buddha kami; anak memanggil ibu, ibu mendengarnya. </b><br>-Orang yang benar-benar bisa memiliki kebijaksanaan, dia adalah Bodhisattva (Kedua), Ceramah Hong Kong siang 1 Mei 2012- <br><br>Maka hari ini Bodhisattva Guanyin berbicara dengan kalian semua, sebelum berbicara, Master memang harus memberitahu kalian satu hal, karena suara Bodhisattva Guanyin ketika berbicara dengan saya, saya benar-benar merasa aneh, para sutradara film itu, mereka benar-benar sangat hebat, saya tidak tahu bagaimana mereka mendapatkan suara Bodhisattva Guanyin, suara itu mengharukan, penuh welas asih, persis sama dengan yang saya dengar. <br><br>Saya akan menirukan suara itu untuk kalian dengar, baik? \"Para murid, kalian adalah murid-murid Bodhisattva, harap kalian melatih diri dengan baik.\" Wah, welas asih dari suara itu membuat kamu menangis setelah mendengarnya. Tentu saja, sekarang ketika saya melantunkannya, suaranya tidak sebagus itu. <br><br>Sekarang saya beritahu kalian semua, apa yang Bodhisattva katakan untuk kalian semua. \"Penderitaan makhluk hidup, sesungguhnya adalah penderitaan dunia manusia, sedangkan penderitaan dunia manusia, adalah penderitaan Bodhisattva, sesungguhnya hati Bodhisattva terhubung dengan kita semua makhluk hidup, karena Bodhisattva hidup untuk makhluk hidup, sedangkan makhluk hidup adalah Bodhisattva, Bodhisattva menjadi Buddha karena makhluk hidup, Bodhisattva tidak dapat dipisahkan dari makhluk hidup, penderitaan makhluk hidup adalah penderitaan Buddha kami, hanya ketika makhluk hidup mencapai pencerahan, barulah nirvana sejati Buddha dan Bodhisattva.\" <br><br>Ini adalah yang Bodhisattva Guanyin katakan pada Master pagi ini pukul 7:30. Biasanya Bodhisattva Guanyin sering berbicara dengan saya tentang banyak hal, setiap kali ceramah dharma saya selalu menceritakannya. Ini adalah pesan khusus dari Bodhisattva Guanyin untuk kita, yaitu dalam hati Bodhisattva Guanyin yang ada hanyalah makhluk hidup. <br><br>Pada 8 April di ceramah Dharma Sydney, ada seorang pengunjung bertanya, \"Kami membaca sutra, apakah Bodhisattva Guanyin benar-benar mendengar atau tidak?\" Saya bertanya hal ini kepada Bodhisattva Guanyin, akhirnya Bodhisattva Guanyin menjawab Master, \"Anak memanggil ibu, bagaimana mungkin ibu tidak mendengar?\"&nbsp;<br></p>', 1),
(8605, 2960, '<p><b>2. Melatih diri dengan baik, untuk menyelamatkan makhluk hidup. </b><br>-Tidak memperebutkan urusan dunia manusia, coba lihat siapa yang bisa pergi ke surga (Kedua), Ceramah Malaysia 28 Februari 2014- <br><br>Ketika bersujud, harus mengungkapkan perasaan tulus, memanggil Bodhisattva Guanyin seperti memanggil ibu, \"Mama, tolong selamatkan saya! Saya sangat menderita! Mama! Saya tidak ingin lagi berada di dunia manusia! Bodhisattva Guanyin, tolong selamatkan saya! Saya benar-benar tidak ingin bereinkarnasi lagi, biarkan saya terbebas dari penderitaan dunia manusia, saya pasti akan menemani ibu menyebarkan ajaran Buddha di surga!\" <br><br>Ada orang yang akan bertanya mengapa masih harus menyebarkan ajaran Buddha di surga? Di surga, Tanah Suci Barat, setiap hari ada Mahabodhisattva datang berceramah, setiap hari ada Mahabodhisattva datang menyebarkan ajaran Buddha, membuat lebih banyak Buddha, lebih banyak Bodhisattva dapat lebih memahami hati mereka, membiarkan mereka dari tingkat bawah kelas bawah hingga tingkat menengah kelas menengah, tingkat menengah kelas atas, tingkat atas kelas bawah, tingkat atas kelas menengah... terus-menerus melatih diri, terus-menerus datang ke dunia manusia untuk menyelamatkan orang, yaitu mengandalkan latihan kehidupan sebelumnya kita, mengandalkan kebijaksanaan Buddha yang sudah kita peroleh di surga. <br><br>Jika ingin membuat tingkat pembelajaran Buddha diri kita lebih tinggi, kita harus datang ke dunia manusia untuk menyelamatkan orang! Karena sudah datang ke dunia manusia, mengapa kita tidak melatih diri terlebih dahulu? Setelah melatih diri dengan baik, kita dapat menyelamatkan lebih banyak makhluk hidup, membuat tingkat diri sendiri meningkat.&nbsp;<br></p>', 2),
(8606, 2960, '<p><b>3. Bodhisattva Guanyin XLFM mempelajari semangat \"welas asih menyelamatkan\" Buddha Mahayana. </b><br>-Ceramah Hari Kelahiran Bodhisattva Guanyin, 27 Maret 2016- <br><br>Sekarang di seluruh dunia adalah \"rumah-rumah Buddha Maitreya, setiap rumah tangga Guanyin\". Lihatlah, di dunia ini selama orang yang belajar Buddha tidak ada yang tidak mengenal Bodhisattva Guanyin, lihatlah orang Barat, mereka akan berkata \"Guanyin Guanyin\", mereka semua bisa berbicara. Buddhisme Mahayana Bodhisattva Guanyin, ingatlah, XLFM kita mempelajari Buddhisme Mahayana, Buddhisme Mahayana yaitu semangat welas asih menyelamatkan. Karena Buddhisme Hinayana adalah melatih diri dengan baik, \"Saya tidak tercermar, saya tidak tercermar oleh orang lain yang membuat hati saya sendiri menjadi semakin kotor, saya melatih diri dengan baik\"; maka Buddhisme Mahayana, yaitu \"Saya harus menyelamatkan makhluk hidup, harus welas asih menyelamatkan\". <br><br>Jadi, Bodhisattva Guanyin sudah menjadi pelindung yang penuh kasih sayang di hati umat manusia kita, yaitu melindungi kita masih memiliki hati nurani, hingga hari ini karena kita memiliki hati nurani, kita tidak menyakiti orang lain, kita tidak melukai orang lain, yaitu karena Bodhisattva Guanyin di hati kita, masih memiliki sedikit semangat yang welas asih dan penuh kasih sayang ini.<br></p>', 3),
(8607, 2961, '<p><b>(5). Hal-hal yang perlu diperhatikan pada Hari Kelahiran Bodhisattva Guanyin. <br><br>1. Hal-hal yang perlu diperhatikan pada \"Hari Kelahiran Bodhisattva Guanyin\" dan hari-hari besar lainnya. </b><br>-Ceramah Radio 2 Bab 7, membedakan kebenaran, meninggalkan kepalsuan- <br><br>Banyak pendengar akan bertanya kepada Master, apa yang harus diperhatikan pada hari ulang tahun dan hari pencerahan Bodhisattva Guanyin? <br><br>Pertama, pada hari itu, bangun sedikit lebih pagi, jangan tidur terlalu malam, umumnya pagi hari jam 6, jam 8 adalah waktu terbaik untuk membaca doa. Tentu saja, jika dapat mandi dan membakar dupa di rumah adalah yang terbaik, jika dapat membaca 49 kali Da Bei Zhou, 49 kali Xin Jing, hari itu termasuk kebajikan sempurna. <br><br>Efek sebenarnya, 49 kali Da Bei Zhou, kamu seperti menambah kekuatan dua kali lipat, 49 kali Xin Jing pembacaanmu juga menambah kekuatan dua kali lipat. <br><br>Maka kalian akan bertanya kepada Master, apakah membaca sutra lainnya juga dua kali lipat? Jawabannya pasti, juga sama. <br><br>Semua orang tahu ketika Bodhisattva Guanyin menyelamatkan makhluk hidup, seribu tangan seribu mata, sebenarnya, ini adalah kekuatan dua kali lipat. Jika kita dapat pada hari itu, juga tanggal 1 dan 15 dapat membaca lebih banyak sutra, kita juga sama dengan memiliki kekuatan dua kali lipat, tetapi kekuatan ini adalah untuk diri sendiri. <br><br>Misalnya, membaca Da Bei Zhou untuk diri sendiri, kekuatan ini adalah berlipat ganda. Tetapi jika membaca untuk orang lain, hanya ada bantuan jodoh. <br><br>Misalnya, Da Bei Zhou dalam XFZ, tidak bisa hanya membaca 49 kali, lalu menjadi 98. Selain itu, ketika membaca sutra, harus dengan tulus memohon kepada Bodhisattva Guanyin, apa yang kamu mohon, kamu lihat manjur atau tidak. <br><br>Misalnya, banyak orang ingin hal yang mereka mohon cepat dikabulkan, maka persembahkan lebih banyak buah; persembahkan lebih banyak bunga, akan membuat kulitmu semakin bersih, orang akan cantik; atau, ada orang yang memohon kekayaan, juga bisa memohon pada hari itu. <br><br>Banyak orang tahu, pada hari ulang tahun Bodhisattva Guanyin, hari pencapaian, harus makan vegetarian. Selain itu, berikrar, kertas bimbingan spiritual, dan melepaskan hewan juga sangat baik. Yang harus dihindari adalah jangan berhubungan suami istri, karena hari itu sebaiknya tidak ada urusan suami istri. <br><br>Harap semua dapat saling memberitahu, saling mendorong, kita bersyukur kepada Bodhisattva Guanyin yang agung, begitu welas asih, datang ke dunia manusia untuk menyelamatkan kita. Bodhisattva Guanyin benar-benar sangat baik, sangat welas asih, kita semua harus mempelajari welas asih besar Bodhisattva Guanyin.&nbsp;<br></p>', 1),
(8608, 2961, '<p><b>2. Di \"Hari Kelahiran Bodhisattva Guanyin\" dapat seperti malam tahun baru membakar dupa pertama membaca sutra. </b><br>-Acara tanya jawab, 19 Februari 2012- <br><br>Penelepon: Pada tanggal 19 bulan 2 lunar, apa bisa seperti malam imlek, membakar dupa pertama, dan membaca sutra? <br><br>Master: Seharusnya bisa. Hari itu adalah kelahiran Bodhisattva Guanyin, di surga banyak dewa pelindung, banyak Bodhisattva besar semuanya sangat senang. Bodhisattva Guanyin yang begitu agung berulang tahun, menurutmu siapa yang tidak senang? <br><br>Penelepon: Apa kita bisa seperti malam imlek membaca sutra di jam 12? Karena jika semua Bodhisattva datang, kita juga ingin gunakan kesempatan sebaik ini.) <br><br>Master: Sangat bisa. Saya beritahu kamu, tidak ada hantu jahat, roh jahat yang akan mengganggu pada hari ulang tahun Bodhisattva Guanyin yang agung.&nbsp;<br></p>', 2),
(8609, 2961, '<p><b>3. Harus mandi, membakar dupa, menyembah Buddha di Hari raya Bodhisattva Guanyin, sesuai kemampuan persembahkan bunga dan buah. </b><br>-Acara tanya Jawab, 17 Februari 2012- <br><br>Master: Harap semua setiap kali bertemu hari raya Bodhisattva Guanyin: tanggal 19 bulan 2, 19 bulan 6, 19 bulan 9 lunar, harus mandi, membakar dupa, dan menyembah Buddha. Orang yang lebih banyak persembahkan buah, hal yang dimohon dapat lebih cepat berbuah; lebih banyak persembahkan bunga, dapat membuat diri cantik, juga dapat memberkati hal-hal cepat berbuah, karena bunga juga dapat berbuah.&nbsp;<br></p>', 3),
(8610, 2961, '<p><b>4. Sedapat mungkin menghindari operasi di hari besar Buddha dan Bodhisattva. </b><br>-Acara tanya jawab, 2 September 2018- <br><br>Penelepon: Shifu pernah mengajarkan, memilih hari baik untuk operasi hari apa yang cocok untuk operasi? <br><br>Master: Pagi hari lebih baik. Pilih hari genap, hari ganjil, saya pernah menjelaskannya, kan. <br><br>Penelepon: Sebisa mungkin menghindari hari kelahiran suci Buddha Bodhisattva, tanggal 1 dan 15, begitu? <br><br>Master: Ya. Banyak orang mengira bisa melakukan hal-hal tanggal 1 dan 15 tidak bisa. Urusan dunia manusia jangan dilakukan pada tanggal 1 dan 15 tanggal 1 dan 15 adalah hari Bodhisattva, bukan hari dunia manusia kita. <br><br>Penelepon: Ya. Juga menghindari hari tidak baik di kalender? <br><br>Master: Benar. Hari buruk yang tertulis di kalender artinya memang tidak baik. Penelepon: Mengerti.&nbsp;<br></p>', 4),
(8611, 2961, '<p><b>5. Orang yang lahir di hari Bodhisattva artinya berjodoh dengan Buddha. </b><br>-Acara tanya jawab, 4 Februari 2018- <br><br>Peneleon: Ada praktisi ingin bertanya kepada Shifu, di tiga hari peringatan Bodhisattva Guanyin, yaitu tanggal 19 bulan 2 19 bulan 6, 19 bulan 9, apakah ini memiliki arti khusus? Apakah memiliki arti khusus bagi orang yang lahir pada tanggal 19 lunar? <br><br>Master: Jika sama dengan Bodhisattva Guanyin, pasti memiliki ikatan dengan Buddha, ini pasti, Minta dia untuk lebih baik belajar Buddha. Jika berjodoh dengan Buddha, kamu lahir pada waktu yang sama dengan Buddha, itu cukup baik. Beberapa orang terkenal, orang yang memiliki prestasi, tanggal kelahiran mereka semuanya sangat baik. <br><br>Penelepon: Berarti orang yang lahir pada 19 lunar tidak begitu dalam, kah?) <br><br>Master: Semuanya cukup baik, sangat baik, semuanya berjodoh.&nbsp;<br></p>', 5),
(8612, 2961, '<p><b>6. Makna khusus bagi orang yang meninggal pada hari besar Buddha Bodhisattva. </b><br>-Acara Zhishuo, 14 November 2014- <br><br>Penelepon: Master mengatakan orang yang lahir di tanggal 1 dan 15 atau hari besar Bodhisattva relatif beruntung. Bagaimana bagi orang yang meninggal pada hari besar Bodhisattva, apakah ada makna khusus? <br><br>Master: Ada, ada penjelasan tentang ini.<br><br>Penelepon: Dia juga mendapat berkah kan? <br><br>Master: Benar, juga mendapat berkah. Contohnya seseorang meninggal dan kebetulan itu hari raya Bodhisattva, situasi seperti ini sangat mungkin banyak dewa pelindung Bodhisattva turun dengan welas asih memberikan berkah, ini benar. Meskipun karma burukmu cukup banyak, tetapi misalnya nilai ujianmu hanya 58-59 poin mungkin dibantu naik sampai 60 poin agar lulus; tetapi jika nilaimu 30, meskipun meninggal pada hari besar Bodhisattva, juga tidak bisa ditolong untuk lulus.&nbsp;<br></p>', 6),
(8613, 2961, '<p><b>7. Mengapa ada orang yang menjadi murung setiap tanggal 1, 15, atau hari kelahiran Buddha.</b><br>-Acara tanya jawab, 29 Juni 2018- <br><br>Penelepon: Shifu, ada praktisi menjadi murung, bahkan tidak bisa membaca sutra, setiap tanggal 1, 15, atau hari kelahiran Buddha, mengapa begitu? <br><br>Master: Karena banyak Bodhisattva datang, karma dia sangat berat! Karena \"tidak bisa pulang kampung halaman, tidak bisa bertemu ayah ibu\", seperti itu. <br><br>Penelepon: Mengerti.<br></p>', 7);
